/**
 * Traduit un texte via DeepL Free API
 * @param {string} text   — texte à traduire
 * @param {string} target — code langue DeepL cible (ex: 'EN-GB', 'DE', 'ES')
 * @returns {Promise<string>} texte traduit, ou texte original si erreur/pas de clé
 */
async function translateWithDeepL(text, target) {
  const apiKey = process.env.DEEPL_API_KEY;
  if (!apiKey || !target || !text) return text;

  try {
    const response = await axios.post(
      'https://api-free.deepl.com/v2/translate',
      new URLSearchParams({
        auth_key: apiKey,
        text,
        target_lang: target,
        source_lang: 'FR',
        tag_handling: 'text',
        preserve_formatting: '1',
      }),
      { headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, timeout: 8000 }
    );
    const translated = response.data?.translations?.[0]?.text;
    if (translated) {
      console.log(`🌍 [DEEPL] Traduit vers ${target} (${text.length} chars → ${translated.length} chars)`);
      return translated;
    }
    return text;
  } catch (err) {
    // Ne jamais bloquer l'envoi du message si DeepL échoue
    console.warn(`⚠️ [DEEPL] Erreur traduction ${target}:`, err.response?.data?.message || err.message);
    return text;
  }
}

/**
 * Retourne le code langue DeepL cible à partir du pays ou de la langue du voyageur
 * Retourne null si pays francophone ou inconnu → pas de traduction
 */
function getDeepLTarget(guestCountry, guestLanguage) {
  // Priorité 1 : langue explicite si dispo (ex: "en", "de")
  if (guestLanguage) {
    const lang = guestLanguage.toUpperCase().split('-')[0];
    const LANG_TO_DEEPL = {
      'EN': 'EN-GB', 'DE': 'DE', 'ES': 'ES', 'IT': 'IT', 'NL': 'NL',
      'PT': 'PT-PT', 'PL': 'PL', 'RU': 'RU', 'JA': 'JA', 'ZH': 'ZH',
      'KO': 'KO', 'DA': 'DA', 'SV': 'SV', 'NB': 'NB', 'FI': 'FI',
      'CS': 'CS', 'RO': 'RO', 'HU': 'HU', 'EL': 'EL', 'TR': 'TR',
      'UK': 'UK', 'BG': 'BG', 'SK': 'SK', 'SL': 'SL', 'HR': 'HR',
      'ET': 'ET', 'LV': 'LV', 'LT': 'LT',
    };
    if (LANG_TO_DEEPL[lang]) return LANG_TO_DEEPL[lang];
  }
  // Priorité 2 : code pays
  if (guestCountry) {
    const country = guestCountry.toUpperCase().trim();
    const target = COUNTRY_TO_DEEPL_LANG[country];
    return target ?? null; // null = francophone ou inconnu → pas de traduction
  }
  return null; // pas d'info → pas de traduction
}


// Priorité : internal_name (nom court) → name (nom complet)
// À utiliser partout où on affiche le nom d'un logement
// ============================================================
function displayName(property) {
  if (!property) return 'Logement';
  const n = property.internal_name || property.internalName;
  if (n && String(n).trim() !== '') return String(n).trim();
  return property.name || property.property_name || 'Logement';
}


// Appelé après chaque création/suppression de réservation
// ============================================================
async function triggerChannexAvailabilitySync(propertyId, targetDates = null) {
  // targetDates : tableau de dates YYYY-MM-DD à mettre à jour (mode partiel)
  // Si null → full sync de toutes les dates bloquées (mode legacy)
  try {
    const propResult = await pool.query(
      'SELECT channex_property_id, channex_room_type_id, channex_enabled FROM properties WHERE id = $1',
      [propertyId]
    );

    const prop = propResult.rows[0];
    if (!prop || !prop.channex_enabled || !prop.channex_property_id) return;

    console.log(`🔄 [CHANNEX SYNC] Déclenchement pour ${propertyId} (${targetDates ? targetDates.length + ' dates ciblées' : 'full sync'})`);

    // Récupérer toutes les dates bloquées (pour savoir lesquelles sont dispo ou non)
    const resaResult = await pool.query(
      "SELECT start_date, end_date FROM reservations WHERE property_id = $1 AND status NOT IN ('cancelled')",
      [propertyId]
    );

    const dates_blocked = [];
    resaResult.rows.forEach(r => {
      const start = new Date(r.start_date);
      const end = new Date(r.end_date);
      for (let d = new Date(start); d < end; d.setDate(d.getDate() + 1)) {
        dates_blocked.push(d.toISOString().split('T')[0]);
      }
    });

    await pushAvailability(pool, {
      property_id: propertyId,
      channex_property_id: prop.channex_property_id,
      channex_room_type_id: prop.channex_room_type_id,
      dates_blocked,
      dates_to_update: targetDates  // null = full sync, tableau = mode partiel
    });

    console.log(`✅ [CHANNEX SYNC] Dispos mises à jour (${dates_blocked.length} bloquées, ${targetDates ? targetDates.length + ' envoyées' : 'full sync'})`);

  } catch (e) {
    console.error('⚠️ [CHANNEX SYNC] Erreur (non bloquante):', e.message);
  }
}


// ============================================================
// 💰 CHANNEX — Sync automatique des tarifs
// Appelé après chaque modif de prix/règle/override
// ============================================================
async function triggerChannexRatesSync(propertyId, userId) {
  try {
    const propResult = await pool.query(
      `SELECT id, name, base_price, weekend_price,
              channex_enabled, channex_property_id, channex_room_type_id, channex_rate_plan_id
       FROM properties WHERE id = $1`,
      [propertyId]
    );
    const prop = propResult.rows[0];
    if (!prop || !prop.channex_enabled || !prop.channex_rate_plan_id) return;

    console.log(`💰 [CHANNEX RATES SYNC] Déclenchement pour ${propertyId}`);

    const rulesResult = await pool.query(
      'SELECT * FROM pricing_rules WHERE property_id = $1 AND user_id = $2 AND active = true ORDER BY priority DESC',
      [propertyId, userId]
    );
    const rules = rulesResult.rows;

    const today = new Date();
    const fmt = d => d.toISOString().split('T')[0];
    const endDate = new Date(today); endDate.setDate(today.getDate() + 500);

    const overridesResult = await pool.query(
      `SELECT TO_CHAR(date,'YYYY-MM-DD') as date, price FROM pricing_overrides
       WHERE property_id = $1 AND user_id = $2 AND date >= $3 AND date <= $4`,
      [propertyId, userId, fmt(today), fmt(endDate)]
    );
    const overridesMap = {};
    overridesResult.rows.forEach(o => { overridesMap[o.date] = parseFloat(o.price); });

    const periodRules  = rules.filter(r => r.rule_type === 'period');
    const weekdayRules = rules.filter(r => r.rule_type === 'weekday');
    const minStayRules = rules.filter(r => r.rule_type === 'min_stay');
    const longStayRule = rules.find(r => r.rule_type === 'long_stay') || null;

    const rates = [];
    const restrictions = [];

    for (let i = 0; i < 500; i++) {
      const d = new Date(today);
      d.setDate(today.getDate() + i);
      const dateStr = fmt(d);
      const dow = d.getDay();

      let appliedPrice = null;

      if (overridesMap[dateStr] != null) {
        appliedPrice = overridesMap[dateStr];
      } else {
        for (const rule of periodRules) {
          if (rule.start_date && rule.end_date && rule.price != null) {
            if (dateStr >= fmt(new Date(rule.start_date)) && dateStr <= fmt(new Date(rule.end_date))) {
              appliedPrice = parseFloat(rule.price); break;
            }
          }
        }
        if (appliedPrice === null) {
          for (const rule of weekdayRules) {
            if (rule.days_of_week && rule.price != null && rule.days_of_week.includes(dow)) {
              appliedPrice = parseFloat(rule.price); break;
            }
          }
        }
        if (appliedPrice === null) {
          const isPremium = (dow === 5 || dow === 6);
          appliedPrice = isPremium && prop.weekend_price != null
            ? parseFloat(prop.weekend_price)
            : (prop.base_price != null ? parseFloat(prop.base_price) : null);
        }
        if (appliedPrice != null && longStayRule && longStayRule.discount_pct && longStayRule.discount_after_nights) {
          appliedPrice = Math.round(appliedPrice * (1 - parseFloat(longStayRule.discount_pct) / 100) * 100) / 100;
        }
      }

      if (appliedPrice != null) rates.push({ date: dateStr, price: appliedPrice });

      let minStay = null;
      for (const rule of minStayRules) {
        if (rule.min_nights == null) continue;
        if (!rule.start_date && !rule.end_date && !rule.days_of_week) { minStay = rule.min_nights; break; }
        if (rule.start_date && rule.end_date) {
          if (dateStr >= fmt(new Date(rule.start_date)) && dateStr <= fmt(new Date(rule.end_date))) {
            minStay = rule.min_nights; break;
          }
        }
      }
      if (minStay != null) restrictions.push({ date: dateStr, min_stay: minStay });
    }

    if (rates.length > 0) {
      await pushRates(pool, {
        property_id: propertyId,
        channex_property_id: prop.channex_property_id,
        channex_rate_plan_id: prop.channex_rate_plan_id,
        rates
      });
    }
    if (restrictions.length > 0) {
      await pushRestrictions(pool, {
        property_id: propertyId,
        channex_property_id: prop.channex_property_id,
        channex_room_type_id: prop.channex_room_type_id,
        channex_rate_plan_id: prop.channex_rate_plan_id,
        restrictions
      });
    }

    console.log(`✅ [CHANNEX RATES SYNC] ${rates.length} tarifs + ${restrictions.length} restrictions synchronisés`);
  } catch (e) {
    console.error('⚠️ [CHANNEX RATES SYNC] Erreur (non bloquante):', e.message);
  }
}

