const app = express();

// ✅ Configuration de l'expéditeur des emails
const EMAIL_FROM = process.env.EMAIL_FROM || `"Boostinghost" <no-reply@boostinghost.fr>`;

// Rendre les variables globales disponibles pour les routes
app.locals.pool = pool;

// Augmenter la limite pour les uploads de photos
// ⚠️ COMMENTÉ : bodyParser doit être APRÈS le webhook Stripe (voir ligne 2038-2041)
// app.use(bodyParser.json({ limit: '50mb' }));
// app.use(bodyParser.urlencoded({ limit: '50mb', extended: true }));

// ✅ Healthcheck (pour vérifier que Render sert bien CE serveur)
// ── Annonces / Changelog ────────────────────────────────────────
// ── CORS explicite pour announcements (routes définies avant le middleware global) ──
const corsAnn = require('cors')();

app.options('/api/announcements', corsAnn);
app.options('/api/announcements/:id', corsAnn);

app.get('/api/announcements', corsAnn, authenticateAny, async (req, res) => {
  try {
    const result = await pool.query('SELECT * FROM announcements ORDER BY created_at DESC LIMIT 50');
    res.json({ announcements: result.rows });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.post('/api/announcements', corsAnn, bodyParser.json(), async (req, res) => {
  try {
    const adminKey = req.headers['x-admin-key'] || (req.body && req.body.adminKey);
    if (adminKey !== (process.env.ADMIN_SECRET_KEY || 'bh-admin-2024')) return res.status(403).json({ error: 'Non autorisé' });
    const { title, body, type, status } = req.body || {};
    if (!title || !body) return res.status(400).json({ error: 'title et body requis' });
    const safeType = ['feature','bugfix','maintenance','info'].includes(type) ? type : 'info';
    const safeStatus = ['en_cours','resolu','termine'].includes(status) ? status : 'en_cours';
    const result = await pool.query(
      'INSERT INTO announcements (title, body, type, status) VALUES ($1, $2, $3, $4) RETURNING *',
      [title, body, safeType, safeStatus]
    );
    res.json({ announcement: result.rows[0] });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

app.patch('/api/announcements/:id/status', corsAnn, bodyParser.json(), async (req, res) => {
  try {
    const adminKey = req.headers['x-admin-key'] || (req.body && req.body.adminKey);
    if (adminKey !== (process.env.ADMIN_SECRET_KEY || 'bh-admin-2024')) return res.status(403).json({ error: 'Non autorisé' });
    const { status } = req.body || {};
    const allowed = ['en_cours', 'resolu', 'termine'];
    if (!allowed.includes(status)) return res.status(400).json({ error: 'Statut invalide' });
    const result = await pool.query(
      'UPDATE announcements SET status = $1 WHERE id = $2 RETURNING *',
      [status, req.params.id]
    );
    if (!result.rows.length) return res.status(404).json({ error: 'Annonce non trouvée' });
    res.json({ announcement: result.rows[0] });
  } catch(e) { res.status(500).json({ error: e.message }); }
});

