// GET /api/property-groups — liste des groupes de l'utilisateur
app.get('/api/property-groups', cors(), authenticateAny, async (req, res) => {
  try {
    const userId = req.user.id;
    const result = await pool.query(
      `SELECT id, name, property_ids, created_at, updated_at
       FROM property_groups
       WHERE user_id = $1
       ORDER BY created_at ASC`,
      [userId]
    );
    const groups = result.rows.map(row => ({
      id: row.id,
      name: row.name,
      propertyIds: Array.isArray(row.property_ids) ? row.property_ids : [],
      createdAt: row.created_at,
      updatedAt: row.updated_at,
    }));
    res.json({ groups });
  } catch (err) {
    console.error('❌ [GROUPS] GET error:', err.message);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/property-groups — créer un nouveau groupe
app.post('/api/property-groups', cors(), express.json(), authenticateAny, async (req, res) => {
  try {
    const userId = req.user.id;
    const { id, name, propertyIds } = req.body || {};

    if (!name || typeof name !== 'string' || !name.trim()) {
      return res.status(400).json({ error: 'name is required' });
    }
    if (!Array.isArray(propertyIds)) {
      return res.status(400).json({ error: 'propertyIds must be an array' });
    }

    const groupId = id && typeof id === 'string' && id.trim()
      ? id.trim()
      : 'grp_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);

    await pool.query(
      `INSERT INTO property_groups (id, user_id, name, property_ids, created_at, updated_at)
       VALUES ($1, $2, $3, $4::jsonb, NOW(), NOW())
       ON CONFLICT (id) DO UPDATE
         SET name = EXCLUDED.name,
             property_ids = EXCLUDED.property_ids,
             updated_at = NOW()
         WHERE property_groups.user_id = $2`,
      [groupId, userId, name.trim(), JSON.stringify(propertyIds)]
    );

    res.json({
      success: true,
      group: { id: groupId, name: name.trim(), propertyIds }
    });
  } catch (err) {
    console.error('❌ [GROUPS] POST error:', err.message);
    res.status(500).json({ error: err.message });
  }
});

// PUT /api/property-groups/:id — mettre à jour un groupe
app.put('/api/property-groups/:id', cors(), express.json(), authenticateAny, async (req, res) => {
  try {
    const userId = req.user.id;
    const groupId = req.params.id;
    const { name, propertyIds } = req.body || {};

    const existing = await pool.query(
      'SELECT id FROM property_groups WHERE id = $1 AND user_id = $2',
      [groupId, userId]
    );
    if (existing.rows.length === 0) {
      return res.status(404).json({ error: 'Group not found' });
    }

    const sets = [];
    const values = [];
    let idx = 1;
    if (typeof name === 'string' && name.trim()) {
      sets.push(`name = $${idx++}`);
      values.push(name.trim());
    }
    if (Array.isArray(propertyIds)) {
      sets.push(`property_ids = $${idx++}::jsonb`);
      values.push(JSON.stringify(propertyIds));
    }
    if (sets.length === 0) {
      return res.status(400).json({ error: 'Nothing to update' });
    }
    sets.push(`updated_at = NOW()`);
    values.push(groupId, userId);

    await pool.query(
      `UPDATE property_groups SET ${sets.join(', ')} WHERE id = $${idx++} AND user_id = $${idx}`,
      values
    );

    res.json({ success: true });
  } catch (err) {
    console.error('❌ [GROUPS] PUT error:', err.message);
    res.status(500).json({ error: err.message });
  }
});

// DELETE /api/property-groups/:id — supprimer un groupe
app.delete('/api/property-groups/:id', cors(), authenticateAny, async (req, res) => {
  try {
    const userId = req.user.id;
    const groupId = req.params.id;
    const result = await pool.query(
      'DELETE FROM property_groups WHERE id = $1 AND user_id = $2 RETURNING id',
      [groupId, userId]
    );
    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Group not found' });
    }
    res.json({ success: true });
  } catch (err) {
    console.error('❌ [GROUPS] DELETE error:', err.message);
    res.status(500).json({ error: err.message });
  }
});

// POST /api/property-groups/bulk-import — migration localStorage → DB
app.post('/api/property-groups/bulk-import', cors(), express.json(), authenticateAny, async (req, res) => {
  try {
    const userId = req.user.id;
    const { groups } = req.body || {};

    if (!Array.isArray(groups)) {
      return res.status(400).json({ error: 'groups must be an array' });
    }

    // Ne rien faire si la DB a déjà des groupes (éviter d'écraser)
    const existing = await pool.query(
      'SELECT COUNT(*)::int AS count FROM property_groups WHERE user_id = $1',
      [userId]
    );
    if (existing.rows[0].count > 0) {
      return res.json({
        success: false,
        skipped: true,
        reason: 'groups already exist in DB',
        existingCount: existing.rows[0].count,
      });
    }

    let imported = 0;
    for (const g of groups) {
      if (!g || typeof g !== 'object' || !g.name) continue;
      const groupId = g.id && typeof g.id === 'string'
        ? g.id
        : 'grp_' + Date.now() + '_' + Math.random().toString(36).slice(2, 8);
      const propertyIds = Array.isArray(g.propertyIds) ? g.propertyIds : [];
      await pool.query(
        `INSERT INTO property_groups (id, user_id, name, property_ids, created_at, updated_at)
         VALUES ($1, $2, $3, $4::jsonb, NOW(), NOW())
         ON CONFLICT (id) DO NOTHING`,
        [groupId, userId, String(g.name).trim(), JSON.stringify(propertyIds)]
      );
      imported++;
    }

    res.json({ success: true, imported });
  } catch (err) {
    console.error('❌ [GROUPS] bulk-import error:', err.message);
    res.status(500).json({ error: err.message });
  }
});

// ── DEMO PUBLIQUE : IA chat pour la page /ia.html ──────────────────────
// Rate limit : 10 messages / IP / heure (en mémoire, suffisant pour démo)
const demoAiRateLimit = new Map();
const DEMO_AI_LIMIT_PER_HOUR = 10;
const DEMO_AI_WINDOW_MS = 60 * 60 * 1000;

setInterval(() => {
  const now = Date.now();
  for (const [ip, entry] of demoAiRateLimit.entries()) {
    if (entry.resetAt < now) demoAiRateLimit.delete(ip);
  }
}, 10 * 60 * 1000);

const DEMO_AI_CONTEXT = `
Tu es l'assistant IA de Boostinghost. Tu réponds à un voyageur pour le compte de l'hôte.

INFORMATIONS SUR LE LOGEMENT DE DÉMONSTRATION :
- Nom : Studio cosy près de la gare, Paris
- Capacité : 2 voyageurs maximum
- Adresse : 12 rue de la Paix, 75001 Paris
- Check-in : à partir de 16h00
- Check-out : avant 11h00
- Code d'accès : 4821 (clavier à côté de la porte d'entrée)
- WiFi : réseau "Studio-Guest", mot de passe "WelcomeToParis2026"
- Parking : parking public payant "Parking Vendôme" à 200m (environ 25€/jour)
- Chauffage : thermostat dans le salon, réglé à 20°C par défaut
- Poubelles : locaux à droite du hall, collecte les lundis et jeudis
- Animaux : non autorisés
- Fumeurs : non autorisés dans le logement (balcon OK)
- Restaurant recommandé : "Le Comptoir du Coin", à 5 minutes à pied, cuisine française traditionnelle
- Bar à cocktails recommandé : "Bar Hemingway" au Ritz, 10 minutes à pied
- Métro le plus proche : Opéra (ligne 3, 7, 8), 3 minutes à pied
- Supermarché : Carrefour City à 150m, ouvert jusqu'à 22h

RÈGLES DE RÉPONSE :
1. Réponds toujours dans la langue du voyageur (détecte-la automatiquement).
2. Sois chaleureux, concis, professionnel.
3. Utilise UNIQUEMENT les infos ci-dessus. Si l'info n'est pas dedans, dis poliment que tu vas transférer à l'hôte.
4. Utilise parfois un emoji léger (🏡 🗝️ 🥐 etc.) mais pas systématiquement.
5. Maximum 4 phrases.
`.trim();

app.post('/api/demo/ai-chat', express.json(), async (req, res) => {
  try {
    const ip = (req.headers['x-forwarded-for'] || req.connection?.remoteAddress || 'unknown')
      .toString().split(',')[0].trim();

    // Rate limit
    const now = Date.now();
    let entry = demoAiRateLimit.get(ip);
    if (!entry || entry.resetAt < now) {
      entry = { count: 0, resetAt: now + DEMO_AI_WINDOW_MS };
      demoAiRateLimit.set(ip, entry);
    }
    if (entry.count >= DEMO_AI_LIMIT_PER_HOUR) {
      return res.status(429).json({
        error: 'Trop de messages. Réessayez dans une heure ou créez un compte pour un accès illimité.',
      });
    }
    entry.count++;

    const { message } = req.body || {};
    if (!message || typeof message !== 'string') {
      return res.status(400).json({ error: 'message is required' });
    }
    if (message.length > 500) {
      return res.status(400).json({ error: 'Message trop long (max 500 caractères)' });
    }

    // Anti prompt-injection basique
    const lower = message.toLowerCase();
    if (lower.includes('ignore previous') || lower.includes('system prompt') ||
        (lower.includes('reveal') && lower.includes('instruction'))) {
      return res.json({
        reply: "Je suis l'assistant virtuel du logement. Je peux vous aider pour les horaires, l'accès, le WiFi, les recommandations locales. Que souhaitez-vous savoir ? 🏡",
      });
    }

    const apiKey = process.env.GROQ_API_KEY;
    if (!apiKey) {
      return res.status(500).json({ error: 'GROQ_API_KEY not configured' });
    }

    const groqRes = await fetch('https://api.groq.com/openai/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'llama-3.3-70b-versatile',
        messages: [
          { role: 'system', content: DEMO_AI_CONTEXT },
          { role: 'user', content: message },
        ],
        temperature: 0.6,
        max_tokens: 300,
      }),
    });

    if (!groqRes.ok) {
      const errText = await groqRes.text().catch(() => '');
      console.error('❌ [DEMO AI] Groq error', groqRes.status, errText);
      throw new Error(`Groq ${groqRes.status}`);
    }

    const data = await groqRes.json();
    const reply = data.choices?.[0]?.message?.content?.trim();

    if (!reply) {
      return res.status(500).json({ error: 'Empty AI response' });
    }

    res.json({ reply });

  } catch (err) {
    console.error('❌ [DEMO AI]', err.message);
    res.status(500).json({
      error: 'Demo temporairement indisponible',
      reply: "Oups, la démo est momentanément indisponible. Essayez dans quelques secondes ou créez votre compte pour tester l'IA sur vos propres logements !",
    });
  }
});

