// Stripe
const STRIPE_SECRET_KEY = process.env.STRIPE_SECRET_KEY || null;

// ✅ WEBHOOK STRIPE (AVANT LES AUTRES MIDDLEWARES)
app.post('/api/webhooks/stripe', express.raw({ type: 'application/json' }), async (req, res) => {
  const sig = req.headers['stripe-signature'];
  const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;
  const webhookSecretPlatform = process.env.STRIPE_WEBHOOK_SECRET_PLATFORM;

  if (!webhookSecret && !webhookSecretPlatform) {
    console.error('STRIPE_WEBHOOK_SECRET manquant');
    return res.status(500).send('Webhook secret not configured');
  }

  let event;

  // Essayer les deux secrets : plateforme (cautions) puis Connect (paiements)
  const secretsToTry = [
    { secret: webhookSecretPlatform, label: 'plateforme' },
    { secret: webhookSecret, label: 'connect' }
  ].filter(s => s.secret);

  let lastErr;
  for (const { secret, label } of secretsToTry) {
    try {
      event = stripe.webhooks.constructEvent(req.body, sig, secret);
      console.log(`Webhook valide avec secret ${label}`);
      break;
    } catch (err) {
      lastErr = err;
    }
  }

  if (!event) {
    console.error('Erreur verification webhook:', lastErr.message);
    return res.status(400).send(`Webhook Error: ${lastErr.message}`);
  }

  console.log('✅ Webhook Stripe reçu:', event.type);

  try {
    switch (event.type) {
      case 'checkout.session.completed': {
        const session = event.data.object;
        
        // 🔍 Déterminer le type de session (abonnement, caution, ou paiement)
        const paymentType = session.metadata?.payment_type;
        const depositId = session.metadata?.deposit_id;
        const paymentId = session.metadata?.payment_id;
        // 💰 PAIEMENT DE LOCATION
        if (paymentType === 'location' || paymentId) {
          console.log('Paiement de location detecte');
          try {
            await pool.query(`
              UPDATE payments 
              SET status = 'paid',
                  stripe_payment_intent_id = $1,
                  updated_at = NOW()
              WHERE id = $2 OR stripe_session_id = $3
            `, [session.payment_intent, paymentId, session.id]);
            
            console.log(`Paiement confirme: ${paymentId || session.id}`);

            // 🔔 Notif sous-comptes : paiement reçu
            try {
              const pmtRow = await pool.query(
                `SELECT p.user_id, pr.name as property_name, pr.internal_name as property_internal_name FROM payments p LEFT JOIN properties pr ON pr.id = p.property_id WHERE p.id = $1 OR p.stripe_session_id = $2 LIMIT 1`,
                [paymentId, session.id]
              );
              if (pmtRow.rows.length > 0) {
                const { user_id } = pmtRow.rows[0];
                const property_name = pmtRow.rows[0].property_internal_name || pmtRow.rows[0].property_name;
                const amt = session.amount_total ? (session.amount_total / 100).toFixed(2) + ' €' : '';
                await sendNotificationToSubAccountsOf(
                  user_id, 'can_view_payments',
                  '💳 Paiement reçu' + (property_name ? ` — ${property_name}` : ''),
                  amt ? `${amt} encaissé` : 'Paiement confirmé',
                  { type: 'payment_received' },
                  'notif_sub_payment_received'
                );
              }
            } catch (nErr) { console.error('❌ Notif sous-comptes paiement:', nErr.message); }

            // 🔔 Notif compte principal : paiement reçu
            try {
              const pmtRow2 = await pool.query(
                `SELECT p.user_id, r.guest_name, pr.name as property_name, pr.internal_name as property_internal_name, p.amount_cents
                 FROM payments p
                 LEFT JOIN properties pr ON pr.id = p.property_id
                 LEFT JOIN reservations r ON r.uid = p.reservation_uid
                 WHERE p.id = $1 OR p.stripe_session_id = $2
                 LIMIT 1`,
                [paymentId, session.id]
              );
              if (pmtRow2.rows.length > 0) {
                const { user_id, guest_name, amount_cents } = pmtRow2.rows[0];
                const property_name = pmtRow2.rows[0].property_internal_name || pmtRow2.rows[0].property_name;
                const amt = amount_cents ? (amount_cents / 100).toFixed(2) + ' €' : '';
                const guestLabel = guest_name || 'Voyageur';
                const propLabel = property_name ? ` — ${property_name}` : '';
                const tokensRes = await pool.query(
                  'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1',
                  [user_id]
                );
                for (const tok of tokensRes.rows) {
                  await sendNotification(
                    tok.fcm_token,
                    `💳 Paiement reçu${propLabel}`,
                    `${guestLabel} a payé${amt ? ' ' + amt : ''}`,
                    { type: 'payment_received', paymentId: String(paymentId || '') }
                  );
                }
              }
            } catch (nErr2) { console.error('❌ Notif principale paiement:', nErr2.message); }

          } catch (err) {
            console.error('Erreur mise a jour payment:', err);
          }
          break;
        }
        
        // 🛡️ CAUTION
        if (depositId || session.metadata?.deposit_id) {
          console.log('Caution detectee');
          try {
            // Pour une caution avec capture_method:'manual', checkout.session.completed
            // signifie toujours authorized — pas besoin de retrieve le PI
            const depositStatus = 'authorized';
            
            // Mettre à jour la caution - VERSION SIMPLIFIÉE
            const updateQuery = `
              UPDATE deposits 
              SET status = $1,
                  stripe_payment_intent_id = $2,
                  updated_at = NOW()
              WHERE id = $3 OR stripe_session_id = $4
            `;
            
            const updateResult = await pool.query(updateQuery, [depositStatus, session.payment_intent, depositId, session.id]);
            console.log(`🔄 UPDATE deposits: ${updateResult.rowCount} ligne(s) modifiée(s) (depositId=${depositId}, sessionId=${session.id})`);
            
            // Mettre à jour les timestamps séparément pour éviter les conflits de type
            if (depositStatus === 'authorized') {
              await pool.query(`UPDATE deposits SET authorized_at = NOW() WHERE id = $1 OR stripe_session_id = $2`, [depositId, session.id]);
            } else if (depositStatus === 'captured') {
              await pool.query(`UPDATE deposits SET captured_at = NOW() WHERE id = $1 OR stripe_session_id = $2`, [depositId, session.id]);
            }
            
            console.log(`Caution confirmee: ${depositId} (statut: ${depositStatus})`);
            
            // 🔔 Notif sous-comptes : caution payée
            try {
              const depRow = await pool.query(
                `SELECT d.user_id, pr.name as property_name, pr.internal_name as property_internal_name, d.amount_cents FROM deposits d LEFT JOIN properties pr ON pr.id = d.property_id WHERE d.id = $1 OR d.stripe_session_id = $2 LIMIT 1`,
                [depositId, session.id]
              );
              if (depRow.rows.length > 0) {
                const { user_id, amount_cents } = depRow.rows[0];
                const property_name = depRow.rows[0].property_internal_name || depRow.rows[0].property_name;
                const amt = amount_cents ? (amount_cents / 100).toFixed(2) + ' €' : '';
                await sendNotificationToSubAccountsOf(
                  user_id, 'can_view_deposits',
                  '💰 Caution autorisée' + (property_name ? ` — ${property_name}` : ''),
                  amt ? `${amt} bloqués` : 'Caution confirmée',
                  { type: 'deposit_paid' },
                  'notif_sub_deposit_paid'
                );
              }
            } catch (nErr) { console.error('❌ Notif sous-comptes caution:', nErr.message); }

            // 🔔 Notif compte principal : caution autorisée
            try {
              const depRow2 = await pool.query(
                `SELECT d.user_id, r.guest_name, pr.name as property_name, pr.internal_name as property_internal_name, d.amount_cents
                 FROM deposits d
                 LEFT JOIN properties pr ON pr.id = d.property_id
                 LEFT JOIN reservations r ON r.uid = d.reservation_uid
                 WHERE d.id = $1 OR d.stripe_session_id = $2
                 LIMIT 1`,
                [depositId, session.id]
              );
              if (depRow2.rows.length > 0) {
                const { user_id, guest_name, amount_cents } = depRow2.rows[0];
                const property_name = depRow2.rows[0].property_internal_name || depRow2.rows[0].property_name;
                const amt = amount_cents ? (amount_cents / 100).toFixed(2) + ' €' : '';
                const guestLabel = guest_name || 'Voyageur';
                const propLabel = property_name ? ` — ${property_name}` : '';
                const tokensRes = await pool.query(
                  'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1',
                  [user_id]
                );
                for (const tok of tokensRes.rows) {
                  await sendNotification(
                    tok.fcm_token,
                    `🛡️ Caution autorisée${propLabel}`,
                    `${guestLabel} a validé sa caution${amt ? ' de ' + amt : ''}`,
                    { type: 'deposit_paid', depositId: String(depositId || '') }
                  );
                }
              }
            } catch (nErr2) { console.error('❌ Notif principale caution:', nErr2.message); }

            // 📨 ENVOYER MESSAGE AUTOMATIQUE : CAUTION AUTORISÉE
            if (depositStatus === 'authorized') {
              try {
                await sendDepositAuthorizedMessage(pool, io, depositId);
              } catch (msgError) {
                console.error('❌ Erreur envoi message caution autorisée:', msgError);
              }
            }
            
            // Envoyer automatiquement les infos si c'est bientot l'arrivee
            if (depositId) {
              await handleDepositPaid(depositId, io);
            }
          } catch (err) {
            console.error('Erreur mise a jour deposit:', err);
          }
          break;
        }
        
        // 📝 ABONNEMENT (logique existante)
        const userId = session.client_reference_id || session.metadata?.userId;
        
        if (!userId) {
          console.error('userId manquant dans checkout.session.completed');
          break;
        }

        const subscriptionId = session.subscription;
        const customerId = session.customer;

        // Récupérer l'abonnement Stripe pour vérifier s'il y a un essai gratuit
        const stripeSubscription = await stripe.subscriptions.retrieve(subscriptionId);
        const isTrialing = stripeSubscription.status === 'trialing';
        
        // ✅ AMÉLIORATION : Récupérer le vrai plan depuis le Price ID Stripe
        let plan = session.metadata?.plan;
        
        // Si pas de metadata ou metadata incorrecte, récupérer depuis le Price ID
        if (!plan || plan === 'solo_monthly') {
          const priceId = stripeSubscription.items.data[0]?.price?.id;
          if (priceId) {
            plan = getPlanFromPriceId(priceId);
            console.log(`✅ Plan détecté depuis Price ID: ${priceId} -> ${plan}`);
          } else {
            plan = 'solo_monthly';
            console.warn('⚠️ Aucun Price ID trouvé, utilisation du plan Solo par défaut');
          }
        }
        
        const basePlan = getBasePlanName(plan);
        const subscriptionStatus = isTrialing ? 'trial' : 'active';

        if (isTrialing) {
          // Avec période d'essai
          await pool.query(
            `INSERT INTO subscriptions 
             (user_id, stripe_subscription_id, stripe_customer_id, plan_type, status, trial_start_date, trial_end_date, current_period_end)
             VALUES ($1, $2, $3, $4, 'trial', NOW(), to_timestamp($5), to_timestamp($6))
             ON CONFLICT (user_id) 
             DO UPDATE SET
               stripe_subscription_id = $2,
               stripe_customer_id = $3,
               plan_type = $4,
               status = 'trial',
               trial_start_date = NOW(),
               trial_end_date = to_timestamp($5),
               current_period_end = to_timestamp($6),
               updated_at = NOW()`,
            [userId, subscriptionId, customerId, basePlan, stripeSubscription.trial_end, stripeSubscription.current_period_end]
          );
        } else {
          // Sans période d'essai - abonnement actif immédiatement
          await pool.query(
            `INSERT INTO subscriptions 
             (user_id, stripe_subscription_id, stripe_customer_id, plan_type, status, current_period_end)
             VALUES ($1, $2, $3, $4, 'active', to_timestamp($5))
             ON CONFLICT (user_id) 
             DO UPDATE SET
               stripe_subscription_id = $2,
               stripe_customer_id = $3,
               plan_type = $4,
               status = 'active',
               trial_start_date = NULL,
               trial_end_date = NULL,
               current_period_end = to_timestamp($5),
               updated_at = NOW()`,
            [userId, subscriptionId, customerId, basePlan, stripeSubscription.current_period_end]
          );
        }

        const userResult = await pool.query(
          'SELECT email, first_name FROM users WHERE id = $1',
          [userId]
        );

        if (userResult.rows.length > 0) {
          const userEmail = userResult.rows[0].email;
          const userFirstName = userResult.rows[0].first_name || 'cher membre';
          const planAmount = getPlanAmount(plan);

          if (isTrialing) {
            await sendTrialStartedEmail(userEmail, userFirstName, basePlan, planAmount);
            await logEmailSent(userId, 'trial_started', { plan: basePlan, planAmount });
            console.log(`✅ Essai gratuit démarré pour user ${userId} (plan: ${basePlan})`);
          } else {
            await sendSubscriptionConfirmedEmail(userEmail, userFirstName, basePlan, planAmount);
            await logEmailSent(userId, 'subscription_confirmed', { plan: basePlan, planAmount });
            console.log(`✅ Abonnement actif créé pour user ${userId} (plan: ${basePlan})`);
          }
        }

        break;
      }

      case 'invoice.payment_succeeded': {
        const invoice = event.data.object;
        const subscriptionId = invoice.subscription;
        
        if (!subscriptionId) break;

        const subscription = await stripe.subscriptions.retrieve(subscriptionId);
        const userId = subscription.metadata?.userId;
        const plan = subscription.metadata?.plan;

        if (invoice.billing_reason === 'subscription_create') {
          await pool.query(
            `UPDATE subscriptions 
             SET 
               status = 'active',
               trial_end_date = NULL,
               current_period_end = to_timestamp($1),
               updated_at = NOW()
             WHERE stripe_subscription_id = $2`,
            [subscription.current_period_end, subscriptionId]
          );

          console.log(`✅ Abonnement ACTIF après essai: ${subscriptionId}`);
          
          if (userId) {
            const userResult = await pool.query(
              'SELECT email, first_name FROM users WHERE id = $1',
              [userId]
            );

            if (userResult.rows.length > 0) {
              const userEmail = userResult.rows[0].email;
              const userFirstName = userResult.rows[0].first_name || 'cher membre';
              const basePlan = getBasePlanName(plan || 'solo_monthly');
              const planAmount = getPlanAmount(plan || 'solo_monthly');

              await sendSubscriptionConfirmedEmail(userEmail, userFirstName, basePlan, planAmount);
              await logEmailSent(userId, 'subscription_confirmed', { plan: basePlan, planAmount });
            }
          }
        } else {
          await pool.query(
            `UPDATE subscriptions 
             SET 
               current_period_end = to_timestamp($1),
               updated_at = NOW()
             WHERE stripe_subscription_id = $2`,
            [subscription.current_period_end, subscriptionId]
          );
          
          console.log(`✅ Abonnement renouvelé: ${subscriptionId}`);
        }

        // ── Génération facture BH pour tout paiement réussi ──
        if (userId && invoice.amount_paid > 0) {
          try {
            const amountTTC = invoice.amount_paid / 100;
            const tvaRate   = 20;
            const amountHT  = Math.round((amountTTC / (1 + tvaRate / 100)) * 100) / 100;
            const tvaAmount = Math.round((amountTTC - amountHT) * 100) / 100;

            const userRow = await pool.query(
              'SELECT email, first_name, last_name, company FROM users WHERE id = $1',
              [userId]
            );
            const u = userRow.rows[0] || {};
            const clientName    = [u.first_name, u.last_name].filter(Boolean).join(' ') || 'Client';
            const clientCompany = u.company || '';
            const clientEmail   = u.email || '';

            const invoiceNumber = await generateBHInvoiceNumber();

            const pdfPath = await generateSubscriptionInvoicePDF({
              invoiceNumber,
              planType:            plan || 'solo_monthly',
              amountTTC, amountHT, tvaAmount, tvaRate,
              periodStart:         subscription.current_period_start,
              periodEnd:           subscription.current_period_end,
              paymentDate:         invoice.created,
              stripePaymentIntent: invoice.payment_intent,
              clientName, clientCompany, clientEmail,
              clientAddress: ''
            });

            await pool.query(
              `INSERT INTO subscription_invoices
               (user_id, invoice_number, stripe_invoice_id, plan_type,
                amount_ttc, amount_ht, tva_rate, tva_amount, currency,
                period_start, period_end, payment_date, stripe_payment_intent, file_path, status)
               VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9,
                       to_timestamp($10), to_timestamp($11), to_timestamp($12),
                       $13,$14,'paid')
               ON CONFLICT (invoice_number) DO NOTHING`,
              [
                userId, invoiceNumber, invoice.id, plan || 'solo_monthly',
                amountTTC, amountHT, tvaRate, tvaAmount, invoice.currency,
                subscription.current_period_start, subscription.current_period_end,
                invoice.created, invoice.payment_intent || null, pdfPath
              ]
            );
            console.log(`🧾 Facture BH créée : ${invoiceNumber} (user ${userId})`);
          } catch (invErr) {
            console.error('❌ Erreur génération facture BH:', invErr.message);
          }
        }

        break;
      }

      case 'customer.subscription.updated': {
        const subscription = event.data.object;
        const subscriptionId = subscription.id;

        let status = 'active';
        if (subscription.status === 'trialing') status = 'trial';
        else if (subscription.status === 'canceled') status = 'canceled';
        else if (subscription.status === 'past_due') status = 'past_due';
        else if (subscription.status === 'unpaid') status = 'expired';

        // ✅ Récupérer le nouveau plan depuis le Price ID Stripe (gère les upgrades/downgrades)
        let updatedPlanType = null;
        try {
          const priceId = subscription.items?.data[0]?.price?.id;
          if (priceId) {
            updatedPlanType = getPlanFromPriceId(priceId);
            console.log(`✅ Plan mis à jour depuis Price ID: ${priceId} -> ${updatedPlanType}`);
          }
        } catch(e) {
          console.warn('⚠️ Impossible de lire le plan depuis subscription.updated:', e.message);
        }

        // Vérifier le downgrade : si le nouveau plan a moins de logements inclus
        if (updatedPlanType) {
          const newLimits = getPlanLimits(updatedPlanType);
          const subUserResult = await pool.query(
            'SELECT user_id FROM subscriptions WHERE stripe_subscription_id = $1',
            [subscriptionId]
          );
          if (subUserResult.rows.length > 0) {
            const subUserId = subUserResult.rows[0].user_id;
            const propCountResult = await pool.query(
              'SELECT COUNT(*) AS count FROM properties WHERE user_id = $1',
              [subUserId]
            );
            const propCount = parseInt(propCountResult.rows[0].count, 10);
            if (propCount > newLimits.included && newLimits.extraPrice === null) {
              // Plan Solo avec trop de logements → on bloque le downgrade côté info (Stripe gère le billing)
              console.warn(`⚠️ Downgrade détecté: user ${subUserId} a ${propCount} logements mais le nouveau plan ${updatedPlanType} n'en inclut que ${newLimits.included} et ne permet pas de supplémentaires.`);
            }
          }
        }

        const updateQuery = updatedPlanType
          ? `UPDATE subscriptions SET status = $1, current_period_end = to_timestamp($2), plan_type = $4, updated_at = NOW() WHERE stripe_subscription_id = $3`
          : `UPDATE subscriptions SET status = $1, current_period_end = to_timestamp($2), updated_at = NOW() WHERE stripe_subscription_id = $3`;

        const updateParams = updatedPlanType
          ? [status, subscription.current_period_end, subscriptionId, updatedPlanType]
          : [status, subscription.current_period_end, subscriptionId];

        await pool.query(updateQuery, updateParams);

        console.log(`✅ Abonnement ${subscriptionId} mis à jour: status=${status}${updatedPlanType ? ' plan=' + updatedPlanType : ''}`);
        break;
      }

      case 'customer.subscription.deleted': {
        const subscription = event.data.object;
        const subscriptionId = subscription.id;

        await pool.query(
          `UPDATE subscriptions 
           SET status = 'canceled', updated_at = NOW()
           WHERE stripe_subscription_id = $1`,
          [subscriptionId]
        );

        console.log(`✅ Abonnement ${subscriptionId} annulé`);
        break;
      }

      case 'invoice.payment_failed': {
        const invoice = event.data.object;
        const subscriptionId = invoice.subscription;

        if (subscriptionId) {
          await pool.query(
            `UPDATE subscriptions 
             SET status = 'past_due', updated_at = NOW()
             WHERE stripe_subscription_id = $1`,
            [subscriptionId]
          );

          console.log(`⚠️ Paiement échoué pour: ${subscriptionId}`);
        }
        break;
      }

      // 💰 ÉVÉNEMENTS SPÉCIFIQUES AUX CAUTIONS
      case 'payment_intent.canceled': {
        const paymentIntent = event.data.object;
        
        // Vérifier si c'est une caution
        const depositResult = await pool.query(
          'SELECT id FROM deposits WHERE stripe_payment_intent_id = $1',
          [paymentIntent.id]
        );
        
        if (depositResult.rows.length > 0) {
          const depositId = depositResult.rows[0].id;
          
          await pool.query(
            `UPDATE deposits 
             SET status = 'canceled', cancelled_at = NOW(), updated_at = NOW()
             WHERE id = $1`,
            [depositId]
          );
          
          console.log(`❌ Caution annulée: ${depositId}`);
          
          // 📨 ENVOYER MESSAGE : ÉCHEC
          try {
            await sendDepositFailedMessage(pool, io, depositId);
          } catch (msgError) {
            console.error('❌ Erreur envoi message caution annulée:', msgError);
          }
        }
        break;
      }

      case 'charge.refunded': {
        const charge = event.data.object;
        const paymentIntentId = charge.payment_intent;
        
        // Vérifier si c'est une caution
        const depositResult = await pool.query(
          'SELECT id FROM deposits WHERE stripe_payment_intent_id = $1',
          [paymentIntentId]
        );
        
        if (depositResult.rows.length > 0) {
          const depositId = depositResult.rows[0].id;
          
          await pool.query(
            `UPDATE deposits 
             SET status = 'released', released_at = NOW(), updated_at = NOW()
             WHERE id = $1`,
            [depositId]
          );
          
          console.log(`🎉 Caution libérée: ${depositId}`);
          
          // 📨 ENVOYER MESSAGE : CAUTION LIBÉRÉE
          try {
            await sendDepositReleasedMessage(pool, io, depositId);
          } catch (msgError) {
            console.error('❌ Erreur envoi message caution libérée:', msgError);
          }
        }
        break;
      }

      // 💳 SESSION STRIPE EXPIRÉE (le voyageur n'a pas payé dans le délai)
      case 'checkout.session.expired': {
        const expiredSession = event.data.object;
        const expiredDepositId = expiredSession.metadata?.deposit_id;
        
        if (expiredDepositId) {
          console.log(`⏰ Session Stripe expirée pour caution ${expiredDepositId}`);
          
          // Récupérer le deposit pour vérifier s'il est toujours pending
          const depCheck = await pool.query(
            'SELECT id, status FROM deposits WHERE id = $1',
            [expiredDepositId]
          );
          
          if (depCheck.rows.length > 0 && depCheck.rows[0].status === 'pending') {
            await pool.query(
              `UPDATE deposits SET status = 'expired', updated_at = NOW() WHERE id = $1`,
              [expiredDepositId]
            );
            
            // 📨 Envoyer message d'échec
            try {
              await sendDepositFailedMessage(pool, io, expiredDepositId);
            } catch (msgError) {
              console.error('❌ Erreur envoi message session expirée:', msgError);
            }
          }
        }
        break;
      }

      // 💳 PAIEMENT ÉCHOUÉ (carte refusée, fonds insuffisants, etc.)
      case 'payment_intent.payment_failed': {
        const failedIntent = event.data.object;
        
        // Vérifier si c'est une caution
        const failedDepositResult = await pool.query(
          'SELECT id, status FROM deposits WHERE stripe_payment_intent_id = $1',
          [failedIntent.id]
        );
        
        if (failedDepositResult.rows.length > 0) {
          const failedDepositId = failedDepositResult.rows[0].id;
          const failReason = failedIntent.last_payment_error?.message || 'Paiement refusé';
          
          console.log(`❌ Paiement échoué pour caution ${failedDepositId}: ${failReason}`);
          
          // 📨 Envoyer message d'échec
          try {
            await sendDepositFailedMessage(pool, io, failedDepositId);
          } catch (msgError) {
            console.error('❌ Erreur envoi message paiement échoué:', msgError);
          }
        }
        break;
      }
    }

    res.status(200).json({ received: true });
  } catch (error) {
    console.error('❌ Erreur traitement webhook:', error);
    res.status(500).json({ error: 'Webhook processing error' });
  }
});

