// ROUTE CORRIGÉE : /api/reservations-with-deposits
// AVEC INFOS VOYAGEUR (guest_first_name, guest_last_name)
// ============================================
// Remplacer la route existante dans server.js (vers ligne 6421)

app.get('/api/reservations-with-deposits', authenticateAny, loadSubAccountData(pool), async (req, res) => {
  try {
    // Gérer compte principal ET sous-compte
    let userId;
    
    if (req.user.isSubAccount) {
      // C'est un sous-compte - récupérer le parent_user_id
      const subAccountResult = await pool.query(
        'SELECT parent_user_id FROM sub_accounts WHERE id = $1',
        [req.user.subAccountId]
      );
      
      if (subAccountResult.rows.length === 0) {
        return res.status(404).json({ error: 'Sous-compte introuvable' });
      }
      
      userId = subAccountResult.rows[0].parent_user_id;
      console.log('🔐 Sous-compte - userId parent:', userId);
    } else {
      // Compte principal
      userId = req.user.id;
      console.log('👤 Compte principal - userId:', userId);
    }

    // Vérifier que userId existe
    if (!userId) {
      return res.status(401).json({ error: 'Non autorisé' });
    }

    // ✅ Récupérer tous les deposits de l'utilisateur depuis PostgreSQL
    const depositsResult = await pool.query(`
      SELECT id, reservation_uid, amount_cents, status, checkout_url, stripe_session_id, created_at
      FROM deposits
      WHERE user_id = $1
    `, [userId]);
    
    // Créer un Map pour un accès rapide par reservationUid
    const depositsMap = new Map();
    depositsResult.rows.forEach(d => {
      depositsMap.set(d.reservation_uid, {
        id: d.id,
        amountCents: d.amount_cents,
        status: d.status,
        checkoutUrl: d.checkout_url,
        stripeSessionId: d.stripe_session_id,
        createdAt: d.created_at
      });
    });

    // Récupérer toutes les réservations enrichies depuis la DB (Channex + directes)
    const dbResResult = await pool.query(`
      SELECT
        r.uid, r.property_id, r.start_date, r.end_date,
        r.guest_name, r.guest_first_name, r.guest_last_name,
        r.guest_email, r.guest_phone, r.guest_country,
        r.occupancy_adults, r.occupancy_children,
        r.amount_total, r.amount_rooms, r.amount_taxes,
        r.amount_cleaning, r.ota_commission, r.host_payout,
        r.days_breakdown, r.currency, r.source,
        r.channex_booking_id, r.ota_name,
        p.name as prop_name
      FROM reservations r
      LEFT JOIN properties p ON p.id = r.property_id
      WHERE r.user_id = $1
    `, [userId]);
    
    // Index par uid et par property+date pour matching
    const dbResMap = new Map();
    dbResResult.rows.forEach(r => {
      dbResMap.set(r.uid, r);
      if (r.channex_booking_id) dbResMap.set('CHX_' + r.channex_booking_id, r);
      if (r.start_date) {
        const d = r.start_date.toISOString ? r.start_date.toISOString().split('T')[0] : String(r.start_date).split('T')[0];
        dbResMap.set(r.property_id + '_' + d, r);
      }
    });

    const result = [];
    let userProps = getUserProperties(userId);

    // ✅ Filtrer par propriétés accessibles si sous-compte
    if (req.user.isSubAccount && req.subAccountData?.accessible_property_ids?.length > 0) {
      userProps = userProps.filter(p => 
        req.subAccountData.accessible_property_ids.includes(p.id)
      );
      console.log('🔐 Sous-compte - propriétés filtrées:', userProps.map(p => p.id));
    }

    userProps.forEach(property => {
      const reservations = reservationsStore.properties[property.id] || [];

      reservations.forEach(r => {
        // ✅ Chercher le deposit dans la Map
        const deposit = depositsMap.get(r.uid) || null;
        
        // Chercher les données enrichies dans la DB
        const startDate = r.start ? new Date(r.start).toISOString().split('T')[0] : '';
        const dbData = dbResMap.get(r.uid)
          || dbResMap.get(property.id + '_' + startDate)
          || null;

        // Nom complet du voyageur
        const guestFirstName = (dbData?.guest_first_name) || '';
        const guestLastName  = (dbData?.guest_last_name)  || '';
        const guestPhone     = (dbData?.guest_phone)      || '';
        const guestEmail     = (dbData?.guest_email)      || '';
        let guestDisplayName = guestFirstName
          ? (guestLastName ? guestFirstName + ' ' + guestLastName : guestFirstName)
          : (dbData?.guest_name || r.guestName || '');

        result.push({
          reservationUid: r.uid,
          propertyId: property.id,
          propertyName: displayName(property),
          startDate: r.start,
          endDate: r.end,
          guestName: guestDisplayName || r.guestName || '',
          guestFirstName,
          guestLastName,
          guestDisplayName,
          guestPhone,
          guestEmail,
          guestCountry:      dbData?.guest_country      || null,
          guestAddress:      dbData?.guest_address      || null,
          guestZip:          dbData?.guest_zip          || null,
          occupancyAdults:   dbData?.occupancy_adults   || null,
          occupancyChildren: dbData?.occupancy_children || 0,
          amountTotal:    dbData?.amount_total    ? parseFloat(dbData.amount_total)    : null,
          amountRooms:    dbData?.amount_rooms    ? parseFloat(dbData.amount_rooms)    : null,
          amountTaxes:    dbData?.amount_taxes    ? parseFloat(dbData.amount_taxes)    : null,
          amountCleaning: dbData?.amount_cleaning ? parseFloat(dbData.amount_cleaning) : null,
          otaCommission:  dbData?.ota_commission  ? parseFloat(dbData.ota_commission)  : null,
          hostPayout:     dbData?.host_payout     ? parseFloat(dbData.host_payout)     : null,
          currency: dbData?.currency || 'EUR',
          source: r.source || dbData?.source || '',
          deposit: deposit
            ? {
                id: deposit.id,
                amountCents: deposit.amountCents,
                status: deposit.status,
                checkoutUrl: deposit.checkoutUrl,
                createdAt: deposit.createdAt
              }
            : null
        });
      });
    });

    // Ajouter les résas Channex absentes du store iCal
    const storeUids = new Set(result.map(r => r.reservationUid).filter(Boolean));
    for (const [key, dbData] of dbResMap.entries()) {
      if (!key.startsWith('CHX_') && !key.includes('_20')) {
        if (dbData.source === 'channex' && !storeUids.has(dbData.uid)) {
          const prop = userProps.find(p => p.id === dbData.property_id);
          if (!prop) continue;
          const deposit = depositsMap.get(dbData.uid) || null;
          const startD = dbData.start_date ? (dbData.start_date.toISOString ? dbData.start_date.toISOString() : String(dbData.start_date)) : null;
          const endD   = dbData.end_date   ? (dbData.end_date.toISOString   ? dbData.end_date.toISOString()   : String(dbData.end_date))   : null;
          const gFirst = dbData.guest_first_name || '';
          const gLast  = dbData.guest_last_name  || '';
          const gDisplay = gFirst ? (gLast ? gFirst + ' ' + gLast : gFirst) : (dbData.guest_name || '');
          result.push({
            reservationUid: dbData.uid,
            propertyId: prop.id,
            propertyName: displayName(prop),
            startDate: startD,
            endDate:   endD,
            guestName: gDisplay || dbData.guest_name || '',
            guestFirstName:  gFirst,
            guestLastName:   gLast,
            guestDisplayName: gDisplay,
            guestPhone:      dbData.guest_phone  || '',
            guestEmail:      dbData.guest_email  || '',
            guestCountry:    dbData.guest_country || null,
            guestAddress:    dbData.guest_address || null,
            guestZip:        dbData.guest_zip     || null,
            occupancyAdults:   dbData.occupancy_adults   || null,
            occupancyChildren: dbData.occupancy_children || 0,
            amountTotal:    dbData.amount_total    ? parseFloat(dbData.amount_total)    : null,
            amountRooms:    dbData.amount_rooms    ? parseFloat(dbData.amount_rooms)    : null,
            amountTaxes:    dbData.amount_taxes    ? parseFloat(dbData.amount_taxes)    : null,
            amountCleaning: dbData.amount_cleaning ? parseFloat(dbData.amount_cleaning) : null,
            otaCommission:  dbData.ota_commission  ? parseFloat(dbData.ota_commission)  : null,
            currency: dbData.currency || 'EUR',
            source: dbData.ota_name || dbData.source || 'channex',
            deposit: deposit ? {
              id: deposit.id, amountCents: deposit.amountCents,
              status: deposit.status, checkoutUrl: deposit.checkoutUrl,
              createdAt: deposit.createdAt
            } : null
          });
          storeUids.add(dbData.uid);
        }
      }
    }

    console.log('✅ Deposits chargés:', result.length, 'réservations');
    res.json(result);
    
  } catch (error) {
    console.error('❌ Erreur /api/reservations-with-deposits:', error);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// GET /api/reservations-with-payments
// Même structure que reservations-with-deposits mais avec payments
// ============================================
app.get('/api/reservations-with-payments', authenticateAny, requirePermission(pool, 'can_view_payments'), loadSubAccountData(pool), async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;

    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    // Charger tous les paiements de l'utilisateur depuis PostgreSQL
    const paymentsResult = await pool.query(
      'SELECT * FROM payments WHERE user_id = $1 ORDER BY created_at DESC',
      [userId]
    );
    const paymentsRows = paymentsResult.rows;

    // Indexer par reservation_uid
    const paymentByUid = {};
    paymentsRows.forEach(p => {
      if (!paymentByUid[p.reservation_uid]) {
        paymentByUid[p.reservation_uid] = {
          id: p.id,
          amountCents: p.amount_cents,
          status: p.status,
          checkoutUrl: p.checkout_url,
          description: p.metadata?.description || '',
          createdAt: p.created_at
        };
      }
    });

    // Charger toutes les réservations enrichies depuis la DB
    const dbResResult = await pool.query(`
      SELECT r.uid, r.property_id, r.start_date, r.end_date,
        r.guest_name, r.guest_first_name, r.guest_last_name,
        r.guest_email, r.guest_phone, r.guest_country,
        r.occupancy_adults, r.occupancy_children,
        r.amount_total, r.amount_rooms, r.amount_taxes,
        r.amount_cleaning, r.ota_commission, r.host_payout,
        r.currency, r.source, r.channex_booking_id, r.ota_name
      FROM reservations r WHERE r.user_id = $1
    `, [userId]);
    const dbResMap = new Map();
    dbResResult.rows.forEach(r => {
      dbResMap.set(r.uid, r);
      if (r.channex_booking_id) dbResMap.set('CHX_' + r.channex_booking_id, r);
      if (r.start_date) {
        const d = r.start_date.toISOString ? r.start_date.toISOString().split('T')[0] : String(r.start_date).split('T')[0];
        dbResMap.set(r.property_id + '_' + d, r);
      }
    });

    const result = [];
    const userProperties = PROPERTIES.filter(p => p.userId === userId);

    userProperties.forEach(property => {
      const propReservations = reservationsStore.properties[property.id] || [];
      propReservations.forEach(r => {
        if (!r.uid || r.type === 'block' || r.source === 'BLOCK') return;
        const payment = paymentByUid[r.uid] || null;
        const startDate = r.start ? new Date(r.start).toISOString().split('T')[0] : '';
        const dbData = dbResMap.get(r.uid) || dbResMap.get(property.id + '_' + startDate) || null;
        const gFirst = dbData?.guest_first_name || '';
        const gLast  = dbData?.guest_last_name  || '';
        const gDisplay = gFirst ? (gLast ? gFirst + ' ' + gLast : gFirst) : (dbData?.guest_name || r.guestName || '');
        result.push({
          reservationUid: r.uid,
          propertyId: property.id,
          propertyName: displayName(property),
          startDate: r.start,
          endDate: r.end,
          guestName: gDisplay || r.guestName || '',
          guestFirstName:  gFirst,
          guestLastName:   gLast,
          guestDisplayName: gDisplay,
          guestPhone:    dbData?.guest_phone   || '',
          guestEmail:    dbData?.guest_email   || '',
          guestCountry:  dbData?.guest_country || null,
          occupancyAdults:   dbData?.occupancy_adults   || null,
          occupancyChildren: dbData?.occupancy_children || 0,
          amountTotal:    dbData?.amount_total    ? parseFloat(dbData.amount_total)    : null,
          amountRooms:    dbData?.amount_rooms    ? parseFloat(dbData.amount_rooms)    : null,
          amountTaxes:    dbData?.amount_taxes    ? parseFloat(dbData.amount_taxes)    : null,
          amountCleaning: dbData?.amount_cleaning ? parseFloat(dbData.amount_cleaning) : null,
          otaCommission:  dbData?.ota_commission  ? parseFloat(dbData.ota_commission)  : null,
          currency: dbData?.currency || 'EUR',
          source: r.source || dbData?.source || '',
          payment
        });
      });
    });

    // Ajouter les résas Channex absentes du store iCal
    const storeUids = new Set(result.map(r => r.reservationUid));
    for (const [key, dbData] of dbResMap.entries()) {
      if (!key.startsWith('CHX_') && !key.includes('_20')) {
        if (dbData.source === 'channex' && !storeUids.has(dbData.uid)) {
          const prop = userProperties.find(p => p.id === dbData.property_id);
          if (!prop) continue;
          const payment = paymentByUid[dbData.uid] || null;
          const startD = dbData.start_date ? (dbData.start_date.toISOString ? dbData.start_date.toISOString() : String(dbData.start_date)) : null;
          const endD   = dbData.end_date   ? (dbData.end_date.toISOString   ? dbData.end_date.toISOString()   : String(dbData.end_date))   : null;
          const gFirst = dbData.guest_first_name || '';
          const gLast  = dbData.guest_last_name  || '';
          const gDisplay = gFirst ? (gLast ? gFirst + ' ' + gLast : gFirst) : (dbData.guest_name || '');
          result.push({
            reservationUid: dbData.uid,
            propertyId: prop.id, propertyName: displayName(prop),
            startDate: startD, endDate: endD,
            guestName: gDisplay || dbData.guest_name || '',
            guestFirstName: gFirst, guestLastName: gLast, guestDisplayName: gDisplay,
            guestPhone: dbData.guest_phone || '', guestEmail: dbData.guest_email || '',
            guestCountry: dbData.guest_country || null,
            guestAddress: dbData.guest_address || null,
            guestZip:     dbData.guest_zip     || null,
            occupancyAdults: dbData.occupancy_adults || null,
            occupancyChildren: dbData.occupancy_children || 0,
            amountTotal:    dbData.amount_total    ? parseFloat(dbData.amount_total)    : null,
            amountRooms:    dbData.amount_rooms    ? parseFloat(dbData.amount_rooms)    : null,
            amountTaxes:    dbData.amount_taxes    ? parseFloat(dbData.amount_taxes)    : null,
            amountCleaning: dbData.amount_cleaning ? parseFloat(dbData.amount_cleaning) : null,
            otaCommission:  dbData.ota_commission  ? parseFloat(dbData.ota_commission)  : null,
            currency: dbData.currency || 'EUR',
            source: dbData.ota_name || dbData.source || 'channex',
            payment
          });
          storeUids.add(dbData.uid);
        }
      }
    }

    // Trier: paiements en premier, puis par date de début
    result.sort((a, b) => {
      if (a.payment && !b.payment) return -1;
      if (!a.payment && b.payment) return 1;
      return new Date(a.startDate) - new Date(b.startDate);
    });

    res.json(result);
  } catch (error) {
    console.error('❌ Erreur /api/reservations-with-payments:', error);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// ✅ GET - Réservations enrichies (risque + checklist + sous-scores)
// ============================================
app.get('/api/reservations/enriched', authenticateAny, checkSubscription, async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) return res.status(401).json({ error: 'Non autorisé' });

  try {
    // Pré-calcul turnover par property
    const turnoverByUid = new Map();

    const userProps = PROPERTIES.filter(p => p.userId === user.id);

    for (const property of userProps) {
      const list = (reservationsStore.properties[property.id] || [])
        .filter(r => r && r.start && r.end && r.type !== 'block' && r.source !== 'BLOCK');

      const sorted = [...list].sort((a, b) => new Date(a.start) - new Date(b.start));
      for (let i = 0; i < sorted.length; i++) {
        const cur = sorted[i];
        const prev = sorted[i - 1];
        if (!prev) continue;
        const gapHours = (new Date(cur.start) - new Date(prev.end)) / (1000 * 60 * 60);
        turnoverByUid.set(cur.uid, gapHours);
      }
    }

    const now = new Date();
    const result = [];

    for (const property of userProps) {
      const reservations = (reservationsStore.properties[property.id] || [])
        .filter(r => r && r.start && r.end && r.type !== 'block' && r.source !== 'BLOCK');

      for (const r of reservations) {
        // ✅ Checklist V1 auto (lazy)
        const chk = ensureChecklistForReservation({
          reservationUid: r.uid,
          propertyId: property.id,
          userId: userId
        });

        // ✅ Deposit (Stripe) via DEPOSITS JSON
        const dep = DEPOSITS.find(d => d.reservationUid === r.uid) || null;

        const channel = mapChannelFromReservation(r);

        const input = {
          startDate: r.start,
          endDate: r.end,
          bookedAt: r.createdAt || null,
          channel,
          checklistStatus: mapChecklistStatusFromChecklist(chk),
          depositStatus: mapDepositStatusFromDeposit(dep),

          // Champs optionnels (chemin A : defaults)
          propertySensitive: false,
          capacity: 2,
          propertyType: 'entire',
          expectedCheckinHour: parseHour(property.arrivalTime || property.arrival_time),
          turnoverHoursBefore: turnoverByUid.has(r.uid) ? turnoverByUid.get(r.uid) : null,
          lastIcalSyncAt: reservationsStore.lastSync || null,
        };

        const risk = computeRiskV1(input, now);

        result.push({
          ...r,
          propertyId: property.id,
          propertyName: displayName(property),
          deposit: dep,
          checklist: chk,

          riskScore: risk.score,
          riskLevel: risk.level,
          riskLabel: risk.label,
          riskSummary: risk.summary,
          riskTags: risk.tags,
          riskSubScores: risk.subScores,
          riskParts: risk.parts
        });
      }
    }

    // Tri : risque desc puis date
    result.sort((a, b) => (b.riskScore - a.riskScore) || (new Date(a.start) - new Date(b.start)));

    // Persister checklists si de nouvelles ont été créées
    await saveChecklists();

    res.json({ reservations: result });
  } catch (err) {
    console.error('Erreur /api/reservations/enriched :', err);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});

// ============================================
// ✅ Checklists V1 - toggle task
// ============================================
app.post('/api/checklists/:reservationUid/tasks/:taskId/toggle', authenticateAny, checkSubscription, async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) return res.status(401).json({ error: 'Non autorisé' });

  const { reservationUid, taskId } = req.params;
  const chk = CHECKLISTS[reservationUid];
  if (!chk) return res.status(404).json({ error: 'Checklist introuvable' });
  if (chk.userId !== user.id) return res.status(403).json({ error: 'Accès refusé' });

  const task = chk.tasks.find(t => t.id === taskId);
  if (!task) return res.status(404).json({ error: 'Tâche introuvable' });

  task.completed = !task.completed;
  chk.updatedAt = new Date().toISOString();

  const allDone = chk.tasks.every(t => t.completed);
  chk.status = allDone ? 'completed' : (chk.tasks.some(t => t.completed) ? 'in_progress' : 'pending');

  await saveChecklists();
  res.json({ checklist: chk });
});

// ✅ Checklists V1 - complete all
app.post('/api/checklists/:reservationUid/complete', authenticateAny, checkSubscription, async (req, res) => {
  const user = await getUserFromRequest(req);
  if (!user) return res.status(401).json({ error: 'Non autorisé' });

  const { reservationUid } = req.params;
  const chk = CHECKLISTS[reservationUid];
  if (!chk) return res.status(404).json({ error: 'Checklist introuvable' });
  if (chk.userId !== user.id) return res.status(403).json({ error: 'Accès refusé' });

  chk.tasks = chk.tasks.map(t => ({ ...t, completed: true }));
  chk.status = 'completed';
  chk.updatedAt = new Date().toISOString();

  await saveChecklists();
  
  // ✅ Envoyer notification push au propriétaire
  if (await shouldSendNotification(user.id, 'notif_checklist_done')) {
  try {
    const tokensResult = await pool.query(
      'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1',
      [user.id]
    );
    
    if (tokensResult.rows.length > 0) {
      const propertyName = chk.propertyName || chk.title || 'Logement';
      const notifData = {
        type: 'cleaning_completed',
        reservation_uid: reservationUid,
        property_name: propertyName
      };
      for (const tok of tokensResult.rows) {
        await sendNotification(
          tok.fcm_token,
          '✅ Ménage terminé',
          `${propertyName} - Checklist complétée`,
          notifData
        );
      }
      console.log(`✅ Notification ménage complété envoyée pour ${propertyName} (${tokensResult.rows.length} appareil(s))`);
    }
  } catch (notifError) {
    console.error('❌ Erreur notification ménage complété:', notifError.message);
  }
  } // end shouldSendNotification
  
  res.json({ checklist: chk });
});


