// POST - Créer une caution Stripe pour une réservation (empreinte bancaire)
app.post('/api/deposits', 
  authenticateAny,
  requirePermission(pool, 'can_manage_deposits'),
  loadSubAccountData(pool),
  async (req, res) => {
  try {
    const userId = req.user.isSubAccount 
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    
    if (!userId) {
      return res.status(401).json({ error: 'Non autorisé' });
    }

    if (!stripe) {
      return res.status(500).json({ error: 'Stripe non configuré (clé secrète manquante)' });
    }

    const { reservationUid, amount, freeMode, clientName, propertyId: freePropertyId, ownerId: freeOwnerId } = req.body;

    if (!reservationUid || !amount || amount <= 0) {
      return res.status(400).json({ error: 'reservationUid et montant (>0) sont requis' });
    }

    // Retrouver la réservation (sauf en mode libre)
    let reservation = null;
    let property = null;

    if (!freeMode && !reservationUid.startsWith('free_')) {
      const result = findReservationByUidForUser(reservationUid, userId);
      if (!result) {
        return res.status(404).json({ error: 'Réservation non trouvée pour cet utilisateur' });
      }
      reservation = result.reservation;
      property = result.property;
    }

    // ✅ En freeMode : résoudre le propertyId depuis le body ou via ownerId
    let freeModePropertyId = null;
    if (freeMode) {
      if (freePropertyId) {
        freeModePropertyId = freePropertyId;
      } else if (freeOwnerId) {
        // Chercher un logement lié à ce propriétaire (le premier suffit pour le Stripe)
        const propRes = await pool.query(
          'SELECT id FROM properties WHERE owner_id = $1 AND user_id = $2 LIMIT 1',
          [freeOwnerId, userId]
        );
        freeModePropertyId = propRes.rows[0]?.id || null;
      }
    }

    const amountCents = Math.round(amount * 100);

    // Créer l'objet "caution"
    const depositId = 'dep_' + Date.now().toString(36);
    const deposit = {
      id: depositId,
      reservationUid,
      amountCents,
      currency: 'eur',
      status: 'pending',
      stripeSessionId: null,
      checkoutUrl: null,
      createdAt: new Date().toISOString(),
      metadata: clientName ? { clientName } : null
    };
    // Sauvegarder en PostgreSQL
  const saved = await saveDepositToDB(deposit, userId, property ? property.id : null);
  
  if (!saved) {
    return res.status(500).json({ error: 'Erreur lors de la sauvegarde' });
  }

    // ✅ Nettoyer l'URL pour éviter les double slashes
    const appUrl = (process.env.APP_URL || 'https://boostinghost.fr').replace(/\/$/, '');

    // ✅ Session avec capture_method: 'manual' mais SANS user_id dans payment_intent_data
    // pour éviter le routing automatique vers Connect
    const sessionParams = {
      mode: 'payment',
      payment_method_types: ['card'],
      line_items: [{
        price_data: {
          currency: 'eur',
          product_data: {
            name: clientName ? `Caution – ${clientName}` : `Caution séjour – ${property ? property.name : 'Logement'}`,
            description: reservation ? `Du ${reservation.start} au ${reservation.end}` : (clientName || 'Caution libre')
          },
          unit_amount: amountCents
        },
        quantity: 1
      }],
      // 🔹 Empreinte bancaire : autorisation non capturée
      payment_intent_data: {
        capture_method: 'manual',
        metadata: {
          deposit_id: deposit.id,
          reservation_uid: reservationUid
          // ⚠️ On enlève user_id pour éviter le routing vers Connect
        }
      },
      // ⚠️ Ne pas mettre user_id dans les metadata session pour éviter le routing Connect
      metadata: {
        deposit_id: deposit.id,
        reservation_uid: reservationUid
      },
      success_url: `${appUrl}/caution-success.html?depositId=${deposit.id}`,
      cancel_url: `${appUrl}/caution-cancel.html?depositId=${deposit.id}`
    };

    let session;

    // ✅ LOGIQUE PRIORITÉ STRIPE : proprio → user → BH (3%)
    const resolvedPropertyId = property ? property.id : freeModePropertyId;
    const stripeTarget = await getStripeForProperty(pool, resolvedPropertyId, userId);
    const sessionOptions = stripeTarget.stripeAccountId
      ? { stripeAccount: stripeTarget.stripeAccountId }
      : {};

    if (stripeTarget.applyFee) {
      // Stripe BH platform : on ajoute 3% de frais
      sessionParams.payment_intent_data.application_fee_amount = Math.round(amountCents * 0.03);
      console.log(`✅ Création caution sur compte plateforme BH (frais 3% : ${sessionParams.payment_intent_data.application_fee_amount} cts)`);
    } else {
      console.log(`✅ Création caution sur Stripe proprio/user : ${stripeTarget.stripeAccountId}`);
    }

    session = await stripe.checkout.sessions.create(sessionParams, sessionOptions);

    deposit.stripeSessionId = session.id;
    deposit.checkoutUrl = session.url;
    // Mettre à jour après création de la session Stripe
deposit.stripeSessionId = session.id;
deposit.checkoutUrl = session.url;

await pool.query(`
  UPDATE deposits 
  SET stripe_session_id = $1, checkout_url = $2, updated_at = NOW()
  WHERE id = $3
`, [session.id, session.url, deposit.id]);

    return res.json({
      deposit,
      checkoutUrl: session.url
    });
  } catch (err) {
    console.error('Erreur création caution:', err);
    return res.status(500).json({
      error: 'Erreur lors de la création de la caution : ' + (err.message || 'Erreur interne Stripe')
    });
  }
});

// ============================================
// PUT - Modifier une caution existante (changer le montant)
// Expire l'ancienne session Stripe et en recrée une nouvelle
// ============================================
app.put('/api/deposits/:depositId',
  authenticateAny,
  requirePermission(pool, 'can_manage_deposits'),
  loadSubAccountData(pool),
  async (req, res) => {
  try {
    const userId = req.user.isSubAccount 
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });
    if (!stripe) return res.status(500).json({ error: 'Stripe non configuré' });

    const { depositId } = req.params;
    const { amount } = req.body;
    if (!amount || amount <= 0) return res.status(400).json({ error: 'Montant invalide' });

    const { rows } = await pool.query('SELECT * FROM deposits WHERE id = $1 AND user_id = $2', [depositId, userId]);
    if (!rows.length) return res.status(404).json({ error: 'Caution introuvable' });

    const existing = rows[0];
    if (existing.status !== 'pending') {
      return res.status(400).json({ error: 'Impossible de modifier une caution déjà traitée (statut : ' + existing.status + ')' });
    }

    // Expirer l'ancienne session Stripe
    if (existing.stripe_session_id) {
      try {
        await stripe.checkout.sessions.expire(existing.stripe_session_id);
        console.log(`✅ Session Stripe ${existing.stripe_session_id} expirée`);
      } catch (expireErr) {
        console.warn('⚠️ Impossible d\'expirer la session Stripe:', expireErr.message);
      }
    }

    const amountCents = Math.round(amount * 100);
    const appUrl = (process.env.APP_URL || 'https://boostinghost.fr').replace(/\/$/, '');

    const session = await stripe.checkout.sessions.create({
      mode: 'payment',
      payment_method_types: ['card'],
      line_items: [{ price_data: { currency: 'eur', product_data: { name: `Caution séjour`, description: `Caution modifiée – ${new Date().toLocaleDateString('fr-FR')}` }, unit_amount: amountCents }, quantity: 1 }],
      payment_intent_data: { capture_method: 'manual', metadata: { deposit_id: existing.id, reservation_uid: existing.reservation_uid } },
      metadata: { deposit_id: existing.id, reservation_uid: existing.reservation_uid, user_id: String(userId) },
      success_url: `${appUrl}/caution-success.html?depositId=${existing.id}`,
      cancel_url: `${appUrl}/caution-cancel.html?depositId=${existing.id}`
    });

    await pool.query('UPDATE deposits SET amount_cents = $1, stripe_session_id = $2, checkout_url = $3, updated_at = NOW() WHERE id = $4', [amountCents, session.id, session.url, existing.id]);
    console.log(`✅ Caution ${existing.id} modifiée : ${existing.amount_cents} → ${amountCents} cents`);
    return res.json({ deposit: { ...existing, amountCents, stripeSessionId: session.id, checkoutUrl: session.url }, checkoutUrl: session.url });
  } catch (err) {
    console.error('Erreur modification caution:', err);
    return res.status(500).json({ error: 'Erreur lors de la modification : ' + (err.message || 'Erreur interne') });
  }
});

// ============================================
// DELETE - Annuler un lien de caution (expire la session Stripe + reset status)
// ============================================
app.delete('/api/deposits/:depositId',
  authenticateAny,
  requirePermission(pool, 'can_manage_deposits'),
  loadSubAccountData(pool),
  async (req, res) => {
  try {
    const userId = req.user.isSubAccount 
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const { depositId } = req.params;
    const { rows } = await pool.query('SELECT * FROM deposits WHERE id = $1 AND user_id = $2', [depositId, userId]);
    if (!rows.length) return res.status(404).json({ error: 'Caution introuvable' });

    const existing = rows[0];
    if (existing.status !== 'pending') {
      return res.status(400).json({ error: 'Seuls les liens en attente peuvent être annulés' });
    }

    // Expirer la session Stripe
    if (existing.stripe_session_id && stripe) {
      try {
        await stripe.checkout.sessions.expire(existing.stripe_session_id);
      } catch (e) {
        console.warn('⚠️ Session déjà expirée:', e.message);
      }
    }

    // Reset en BDD : supprimer le lien mais garder la trace
    await pool.query('UPDATE deposits SET status = $1, checkout_url = NULL, stripe_session_id = NULL, updated_at = NOW() WHERE id = $2', ['cancelled', depositId]);
    console.log(`✅ Lien caution ${depositId} annulé`);
    return res.json({ message: 'Lien de caution annulé' });
  } catch (err) {
    console.error('Erreur DELETE /api/deposits:', err);
    return res.status(500).json({ error: err.message || 'Erreur serveur' });
  }
});

// ============================================
// PUT - Modifier un paiement existant (changer le montant)
// ============================================
app.put('/api/payments/:paymentId',
  authenticateAny,
  requirePermission(pool, 'can_manage_payments'),
  loadSubAccountData(pool),
  async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) return res.status(401).json({ error: 'Non autorisé' });
    if (!stripe) return res.status(500).json({ error: 'Stripe non configuré' });
    if (!user.stripeAccountId) return res.status(400).json({ error: 'Compte Stripe non connecté', needsStripeConnect: true });

    const { paymentId } = req.params;
    const { amount, description } = req.body;
    if (!amount || amount <= 0) return res.status(400).json({ error: 'Montant invalide' });

    const { rows } = await pool.query('SELECT * FROM payments WHERE id = $1 AND user_id = $2', [paymentId, user.id]);
    if (!rows.length) return res.status(404).json({ error: 'Paiement introuvable' });

    const existing = rows[0];
    if (existing.status !== 'pending') {
      return res.status(400).json({ error: 'Impossible de modifier un paiement déjà traité (statut : ' + existing.status + ')' });
    }

    if (existing.stripe_session_id) {
      try {
        await stripe.checkout.sessions.expire(existing.stripe_session_id, {}, { stripeAccount: user.stripeAccountId });
      } catch (e) {
        console.warn('⚠️ Impossible d\'expirer session paiement:', e.message);
      }
    }

    const amountCents = Math.round(amount * 100);
    const platformFee = Math.round(amountCents * 0.08); // ⏸️ Commission en pause — remplacer 0 par platformFee pour réactiver
    const appUrl = (process.env.APP_URL || 'https://boostinghost.com').replace(/\/$/, '');

    const session = await stripe.checkout.sessions.create({
      mode: 'payment',
      payment_method_types: ['card'],
      line_items: [{ price_data: { currency: 'eur', product_data: { name: description || 'Paiement location', description: `Modifié le ${new Date().toLocaleDateString('fr-FR')}` }, unit_amount: amountCents }, quantity: 1 }],
      payment_intent_data: { application_fee_amount: 0, on_behalf_of: user.stripeAccountId, transfer_data: { destination: user.stripeAccountId }, metadata: { payment_id: existing.id, reservation_uid: existing.reservation_uid, payment_type: 'location' } },
      metadata: { payment_id: existing.id, reservation_uid: existing.reservation_uid, user_id: user.id, payment_type: 'location' },
      success_url: `${appUrl}/payment-success.html?session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${appUrl}/cautions-paiements.html?tab=payments`
    });

    await pool.query('UPDATE payments SET amount_cents = $1, stripe_session_id = $2, checkout_url = $3, updated_at = NOW() WHERE id = $4', [amountCents, session.id, session.url, existing.id]);
    console.log(`✅ Paiement ${existing.id} modifié : ${existing.amount_cents} → ${amountCents} cents`);
    return res.json({ payment: { ...existing, amountCents, stripeSessionId: session.id, checkoutUrl: session.url }, checkoutUrl: session.url });
  } catch (err) {
    console.error('Erreur modification paiement:', err);
    return res.status(500).json({ error: 'Erreur lors de la modification : ' + (err.message || 'Erreur interne') });
  }
});

// ============================================
// DELETE - Annuler un lien de paiement
// ============================================
app.delete('/api/payments/:paymentId',
  authenticateAny,
  requirePermission(pool, 'can_manage_payments'),
  loadSubAccountData(pool),
  async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) return res.status(401).json({ error: 'Non autorisé' });

    const { paymentId } = req.params;
    const { rows } = await pool.query('SELECT * FROM payments WHERE id = $1 AND user_id = $2', [paymentId, user.id]);
    if (!rows.length) return res.status(404).json({ error: 'Paiement introuvable' });

    const existing = rows[0];
    if (existing.status !== 'pending') {
      return res.status(400).json({ error: 'Seuls les paiements en attente peuvent être annulés' });
    }

    if (existing.stripe_session_id && stripe && user.stripeAccountId) {
      try {
        await stripe.checkout.sessions.expire(existing.stripe_session_id, {}, { stripeAccount: user.stripeAccountId });
      } catch (e) {
        console.warn('⚠️ Session paiement déjà expirée:', e.message);
      }
    }

    await pool.query('UPDATE payments SET status = $1, checkout_url = NULL, stripe_session_id = NULL, updated_at = NOW() WHERE id = $2', ['canceled', paymentId]);
    console.log(`✅ Lien paiement ${paymentId} annulé`);
    return res.json({ message: 'Lien de paiement annulé' });
  } catch (err) {
    console.error('Erreur DELETE /api/payments:', err);
    return res.status(500).json({ error: err.message || 'Erreur serveur' });
  }
});

// ============================================
// POST - Créer un PAIEMENT de location (Stripe Connect avec commission 8%)
// ============================================
app.post('/api/payments', authenticateAny, requirePermission(pool, 'can_manage_payments'), loadSubAccountData(pool), async (req, res) => {
  try {
    const user = await getUserFromRequest(req);
    if (!user) {
      return res.status(401).json({ error: 'Non autorisé' });
    }

    // ⚠️ VÉRIFIER que l'utilisateur a un compte Stripe Connect
    if (!user.stripeAccountId) {
      return res.status(400).json({ 
        error: 'Vous devez connecter votre compte Stripe pour recevoir des paiements',
        needsStripeConnect: true 
      });
    }

    if (!stripe) {
      return res.status(500).json({ error: 'Stripe non configuré (clé secrète manquante)' });
    }

    const { reservationUid, amount, description, freeMode, clientName } = req.body;

    if (!reservationUid || !amount || amount <= 0) {
      return res.status(400).json({ error: 'reservationUid et montant (>0) sont requis' });
    }

    // Retrouver la réservation (sauf en mode libre)
    let reservation = null;
    let property = null;

    if (!freeMode && !reservationUid.startsWith('free_')) {
      const result = findReservationByUidForUser(reservationUid, user.id);
      if (!result) {
        return res.status(404).json({ error: 'Réservation non trouvée pour cet utilisateur' });
      }
      reservation = result.reservation;
      property = result.property;
    }

    const amountCents = Math.round(amount * 100);
    
    // 💰 Calcul de la commission (8% pour la plateforme) — ⏸️ EN PAUSE
    const platformFee = Math.round(amountCents * 0.08); // ⏸️ Garder pour réactiver plus tard
    const platformFeeActive = 0; // 🔴 PAUSE : remplacer par platformFee pour réactiver la commission
    const ownerReceives = amountCents - platformFeeActive;
    
    // Créer l'objet "payment"
    const paymentId = 'pay_' + Date.now().toString(36);
    const payment = {
      id: paymentId,
      reservationUid,
      amountCents,
      platformFeeCents: platformFee,
      currency: 'eur',
      status: 'pending',
      stripeSessionId: null,
      checkoutUrl: null,
      createdAt: new Date().toISOString(),
      metadata: clientName ? { clientName } : null
    };
    
    // Sauvegarder en PostgreSQL
    const saved = await savePaymentToDB(payment, user.id, property ? property.id : null);
    
    if (!saved) {
      return res.status(500).json({ error: 'Erreur lors de la sauvegarde' });
    }

    const appUrl = (process.env.APP_URL || 'https://boostinghost.com').replace(/\/$/, '');

    // 🎯 Créer une session de paiement sur le compte Stripe Connect du propriétaire
    const session = await stripe.checkout.sessions.create({
      mode: 'payment',
      payment_method_types: ['card'],
      line_items: [{
        price_data: {
          currency: 'eur',
          product_data: {
            name: description || (clientName ? `Paiement – ${clientName}` : (property ? `Location – ${property.name}` : 'Paiement')),
            description: reservation ? `Du ${reservation.start} au ${reservation.end}` : (clientName || 'Paiement libre')
          },
          unit_amount: amountCents
        },
        quantity: 1
      }],
      payment_intent_data: {
        // 💰 Commission de la plateforme (8%)
        application_fee_amount: platformFeeActive, // ⏸️ PAUSE — remplacer par platformFee pour réactiver
        // 🎯 Affiche le nom du compte connecté sur le relevé du client
        on_behalf_of: user.stripeAccountId,
        transfer_data: {
          destination: user.stripeAccountId // 🎯 Le compte du propriétaire
        },
        metadata: {
          payment_id: payment.id,
          reservation_uid: reservationUid,
          property_id: property ? property.id : null,
          user_id: user.id,
          payment_type: 'location'
        }
      },
      metadata: {
        payment_id: payment.id,
        reservation_uid: reservationUid,
        property_id: property ? property.id : null,
        user_id: user.id,
        payment_type: 'location'
      },
      success_url: `${appUrl}/payment-success.html?session_id={CHECKOUT_SESSION_ID}`,
      cancel_url: `${appUrl}/cautions-paiements.html?tab=payments`
    });

    payment.stripeSessionId = session.id;
    payment.checkoutUrl = session.url;
    
    // Mettre à jour après création de la session Stripe
    await pool.query(`
      UPDATE payments 
      SET stripe_session_id = $1, checkout_url = $2, updated_at = NOW()
      WHERE id = $3
    `, [session.id, session.url, payment.id]);

    console.log(`✅ Paiement créé: ${payment.id} - Montant: ${amount}€ - Commission: ${(platformFeeActive/100).toFixed(2)}€ (en pause) - Propriétaire reçoit: ${(ownerReceives/100).toFixed(2)}€`);

    return res.json({
      payment,
      checkoutUrl: session.url,
      amount: amount,
      platformFee: platformFeeActive / 100,
      ownerReceives: ownerReceives / 100
    });
  } catch (err) {
    console.error('Erreur création paiement:', err);
    return res.status(500).json({
      error: 'Erreur lors de la création du paiement : ' + (err.message || 'Erreur interne Stripe')
    });
  }
});

