// Route dédiée pour sauvegarder les raccourcis messages
app.put('/api/properties/:propertyId/quick-replies', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const { propertyId } = req.params;
    const { quickReplies } = req.body;

    if (!Array.isArray(quickReplies)) {
      return res.status(400).json({ error: 'quickReplies doit être un tableau' });
    }

    const cleaned = quickReplies.map(item => {
      // Nouveau format {title, text}
      if (item && typeof item === 'object') {
        const text  = String(item.text  || '').trim();
        const title = String(item.title || '').trim();
        if (!text) return null;
        return { title: title || text.slice(0, 30), text };
      }
      // Ancien format string (rétrocompatibilité)
      const text = String(item).trim();
      return text ? { title: text.slice(0, 30), text } : null;
    }).filter(Boolean).slice(0, 5);

    await pool.query(
      `UPDATE properties SET quick_replies = $1 WHERE id = $2 AND user_id = $3`,
      [JSON.stringify(cleaned), propertyId, userId]
    );

    await loadProperties();
    console.log(`✅ quick-replies sauvegardés pour ${propertyId}:`, cleaned);
    return res.json({ success: true, quickReplies: cleaned });
  } catch(err) {
    console.error('Erreur PUT quick-replies:', err);
    return res.status(500).json({ error: 'Erreur serveur' });
  }
});

app.get('/api/chat/conversations/:convId/quick-context', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const { convId } = req.params;
    const convResult = await pool.query(
      `SELECT c.*, p.quick_replies, r.uid as reservation_uid
       FROM conversations c
       LEFT JOIN properties p ON p.id = c.property_id
       LEFT JOIN reservations r ON (
         (c.channex_booking_id IS NOT NULL AND r.channex_booking_id = c.channex_booking_id)
         OR (c.channex_booking_id IS NULL AND r.property_id = c.property_id AND DATE(r.start_date) = DATE(c.reservation_start_date))
       )
       WHERE c.id = $1 AND c.user_id = $2
       LIMIT 1`,
      [convId, userId]
    );

    if (!convResult.rows.length) return res.json({ quickReplies: [], depositUrl: null });

    const row = convResult.rows[0];
    let quickReplies = row.quick_replies || [];
    if (typeof quickReplies === 'string') { try { quickReplies = JSON.parse(quickReplies); } catch(e) { quickReplies = []; } }
    if (!Array.isArray(quickReplies)) quickReplies = [];

    let depositUrl = null, depositAmountCents = null;
    if (row.reservation_uid) {
      const dep = await pool.query(
        `SELECT checkout_url, amount_cents FROM deposits WHERE reservation_uid = $1 AND user_id = $2 AND status IN ('pending','authorized') ORDER BY created_at DESC LIMIT 1`,
        [row.reservation_uid, userId]
      );
      if (dep.rows.length) { depositUrl = dep.rows[0].checkout_url; depositAmountCents = dep.rows[0].amount_cents; }
    }

    console.log(`✅ quick-context conv ${convId}: ${quickReplies.length} raccourcis, caution: ${depositUrl ? 'oui' : 'non'}`);
    return res.json({ quickReplies, depositUrl, depositAmountCents });
  } catch(err) {
    console.error('Erreur quick-context:', err);
    return res.status(500).json({ error: 'Erreur serveur' });
  }
});

app.delete('/api/chat/conversations/:conversationId', authenticateAny, checkSubscription, async (req, res) => {
  try {
    const userId = req.user.id;
    const { conversationId } = req.params;
    
    // Vérifier que la conversation appartient à l'utilisateur
    const checkResult = await pool.query(
      'SELECT id FROM conversations WHERE id = $1 AND user_id = $2',
      [conversationId, userId]
    );
    
    if (checkResult.rows.length === 0) {
      return res.status(404).json({ error: 'Conversation non trouvée' });
    }
    
    // Supprimer les messages associés
    await pool.query('DELETE FROM messages WHERE conversation_id = $1', [conversationId]);
    
    // Supprimer la conversation
    await pool.query('DELETE FROM conversations WHERE id = $1', [conversationId]);
    
    res.json({ 
      success: true,
      message: 'Conversation supprimée avec succès'
    });
    
  } catch (error) {
    console.error('❌ Erreur suppression conversation:', error);
    res.status(500).json({ error: 'Erreur serveur' });
  }
});
