// ============================================
// CRON JOB : NOTIFICATIONS PUSH QUOTIDIENNES
// ============================================
cron.schedule('0 8 * * *', async () => {
  console.log('======================================== CRON 8H ========================================');
  console.log('CRON 8H: Envoi des notifications quotidiennes');
  console.log('Heure Paris: ' + new Date().toLocaleString('fr-FR', { timeZone: 'Europe/Paris' }));
  try {
    const todayStr = new Intl.DateTimeFormat('fr-CA', {
      timeZone: 'Europe/Paris',
      year: 'numeric', month: '2-digit', day: '2-digit'
    }).format(new Date());

    // Fonction helper : envoyer le resume quotidien a un destinataire
    // parentUserId : proprietaire des logements (pour la requete SQL)
    // tokens       : [{fcm_token}]
    // allowedPropertyIds : null = tous les logements, sinon filtre
    // notifUserId  : id utilise pour shouldSendNotification
    async function sendDailySummaryTo(parentUserId, tokens, allowedPropertyIds, notifUserId) {
      const propertyFilter = (allowedPropertyIds && allowedPropertyIds.length > 0)
        ? 'AND p.id = ANY($3::text[])'
        : '';
      const params = (allowedPropertyIds && allowedPropertyIds.length > 0)
        ? [parentUserId, todayStr, allowedPropertyIds]
        : [parentUserId, todayStr];

      // Arrivees
      const arrivalsResult = await pool.query(
        `SELECT DISTINCT ON (r.id)
          r.id, r.property_id, r.start_date,
          COALESCE(
            NULLIF(TRIM(COALESCE(c.guest_first_name,'') || ' ' || COALESCE(c.guest_last_name,'')), ''),
            r.guest_name,
            'Voyageur ' || COALESCE(r.source, 'direct')
          ) as guest_name,
          p.name as property_name,
          p.internal_name as property_internal_name
         FROM reservations r
         JOIN properties p ON r.property_id = p.id
         LEFT JOIN conversations c ON (c.property_id = r.property_id AND DATE(c.reservation_start_date) = DATE(r.start_date))
         WHERE p.user_id = $1
         AND DATE(r.start_date) = $2
         AND r.status != 'cancelled'
         ${propertyFilter}
         ORDER BY r.id`,
        params
      );
      const arrivalsCount = arrivalsResult.rows.length;

      // Departs
      const departuresResult = await pool.query(
        `SELECT DISTINCT ON (r.id)
          r.id, r.property_id,
          p.name as property_name,
          p.internal_name as property_internal_name
         FROM reservations r
         JOIN properties p ON r.property_id = p.id
         WHERE p.user_id = $1
         AND DATE(r.end_date) = $2
         AND r.status != 'cancelled'
         ${propertyFilter}
         ORDER BY r.id`,
        params
      );
      const uniqueProps = [...new Set(departuresResult.rows.map(d => d.property_internal_name?.trim() || d.property_name))];
      const departuresCount = uniqueProps.length;

      console.log(`CRON 8H user ${parentUserId} (notif:${notifUserId}): ${arrivalsCount} arrivée(s), ${departuresCount} départ(s)`);

      // Une seule notification groupée, envoyée même si tout est à 0
      if (await shouldSendNotification(notifUserId, 'notif_daily_summary')) {
        const arrivalsLine = arrivalsCount > 0
          ? '📥 ' + arrivalsResult.rows.map(a => `${a.property_internal_name?.trim() || a.property_name} — ${a.guest_name || 'Voyageur'}`).join(', ')
          : '📥 Aucune arrivée';
        const departuresLine = departuresCount > 0
          ? '🧹 Ménages : ' + uniqueProps.join(', ')
          : '🧹 Aucun départ';

        const title = `📅 ${arrivalsCount} arrivée(s) · ${departuresCount} départ(s) aujourd'hui`;
        const body = arrivalsLine + ' | ' + departuresLine;

        for (const token of tokens) {
          try {
            await sendNotification(token.fcm_token, title, body,
              { type: 'daily_summary', arrivals: arrivalsCount.toString(), departures: departuresCount.toString() });
          } catch (e) { console.error('Erreur notif résumé quotidien:', e.message); }
        }
        console.log(`✅ CRON 8H résumé envoyé à ${tokens.length} token(s) pour ${notifUserId}`);
      } else {
        console.log(`ℹ️ CRON 8H notif_daily_summary désactivée pour ${notifUserId}`);
      }
    }

    const usersResult = await pool.query(
      `SELECT DISTINCT u.id
       FROM users u
       JOIN user_fcm_tokens t ON u.id = t.user_id
       WHERE t.fcm_token IS NOT NULL AND t.sub_account_id IS NULL`
    );
    console.log('CRON 8H: ' + usersResult.rows.length + ' compte(s) principal(aux)');

    for (const user of usersResult.rows) {
      const tokensResult = await pool.query(
        'SELECT fcm_token, device_type FROM user_fcm_tokens WHERE user_id = $1 AND sub_account_id IS NULL',
        [user.id]
      );
      if (tokensResult.rows.length === 0) continue;
      await sendDailySummaryTo(user.id, tokensResult.rows, null, user.id);
    }

    // 2. Sous-comptes : filtres par logements autorises
    const subAccountsResult = await pool.query(
      `SELECT sa.id as sub_account_id, sa.parent_user_id, uft.fcm_token
       FROM sub_accounts sa
       JOIN user_fcm_tokens uft ON uft.sub_account_id = sa.id
       JOIN sub_account_permissions sap ON sap.sub_account_id = sa.id
       WHERE sa.is_active = TRUE
         AND uft.fcm_token IS NOT NULL
         AND sap.notif_sub_daily_summary = TRUE`
    );
    console.log('CRON 8H: ' + subAccountsResult.rows.length + ' sous-compte(s) avec notif activee');

    // Grouper par sub_account_id
    const subByAccount = {};
    for (const row of subAccountsResult.rows) {
      if (!subByAccount[row.sub_account_id]) {
        subByAccount[row.sub_account_id] = { parentUserId: row.parent_user_id, tokens: [] };
      }
      subByAccount[row.sub_account_id].tokens.push({ fcm_token: row.fcm_token });
    }

    for (const [subAccountId, data] of Object.entries(subByAccount)) {
      const propRows = await pool.query(
        'SELECT property_id FROM sub_account_properties WHERE sub_account_id = $1',
        [subAccountId]
      );
      const allowedPropertyIds = propRows.rows.map(r => r.property_id);
      // Aucun logement assigne = acces total
      const filter = allowedPropertyIds.length > 0 ? allowedPropertyIds : null;
      console.log('CRON 8H sous-compte ' + subAccountId + ' logements: ' + (filter ? filter.join(',') : 'TOUS'));
      await sendDailySummaryTo(data.parentUserId, data.tokens, filter, subAccountId);
    }

    console.log('✅ CRON 8H terminé: Notifications quotidiennes envoyées');
  } catch (error) {
    console.error('❌ ERREUR CRON 8H notifications:', error);
  }
}, {
  timezone: "Europe/Paris"
});

console.log('CRON job notifications configure (tous les jours a 8h)');
// ============================================
// CRON JOB : RAPPELS J-1 A 18H
// ============================================
cron.schedule('0 18 * * *', async () => {
  console.log('CRON: Rappels J-1 a 18h');
  try {
    const usersResult = await pool.query(
      `SELECT DISTINCT u.id 
       FROM users u 
       JOIN user_fcm_tokens t ON u.id = t.user_id 
       WHERE t.fcm_token IS NOT NULL`
    );
    
    for (const user of usersResult.rows) {
      // Recuperer TOUS les tokens
      const tokensResult = await pool.query(
        'SELECT fcm_token, device_type FROM user_fcm_tokens WHERE user_id = $1',
        [user.id]
      );
      
      if (tokensResult.rows.length === 0) continue;
      
      // ✅ Calcul en heure Paris pour éviter le décalage UTC
      const tomorrowStr = new Intl.DateTimeFormat('fr-CA', {
        timeZone: 'Europe/Paris',
        year: 'numeric', month: '2-digit', day: '2-digit'
      }).format(new Date(Date.now() + 86400000)); // aujourd'hui + 1 jour en ms
      const dayAfterStr = new Intl.DateTimeFormat('fr-CA', {
        timeZone: 'Europe/Paris',
        year: 'numeric', month: '2-digit', day: '2-digit'
      }).format(new Date(Date.now() + 2 * 86400000));
      
      // Arrivees de demain
      const arrivalsResult = await pool.query(
        `SELECT 
          r.id, r.uid, r.property_id, r.start_date, r.end_date,
          r.source, r.platform, r.status,
          
          COALESCE(
            NULLIF(TRIM(c.guest_first_name || ' ' || c.guest_last_name), ''),
            r.guest_name,
            'Voyageur ' || COALESCE(r.source, 'direct')
          ) as guest_name,
          
          COALESCE(c.guest_phone, r.guest_phone) as guest_phone,
          
          CASE 
            WHEN c.guest_first_name IS NOT NULL 
            THEN LEFT(UPPER(c.guest_first_name), 1)
            ELSE 'V'
          END as guest_initial,
          
          p.name as property_name,
          p.color as property_color
          
         FROM reservations r
         JOIN properties p ON r.property_id = p.id
         LEFT JOIN conversations c ON (
           c.property_id = r.property_id 
           AND DATE(c.reservation_start_date) = DATE(r.start_date)
           AND LOWER(c.platform) = LOWER(r.source)
         )
         WHERE p.user_id = $1 
         AND r.start_date >= $2 
         AND r.start_date < $3
         AND r.status != 'cancelled'`,
        [user.id, tomorrowStr, dayAfterStr]
      );
      
      const count = arrivalsResult.rows.length;
      
      if (count > 0) {
        const propertiesList = arrivalsResult.rows
          .map(a => `${a.property_name} - ${a.guest_name || 'Voyageur'}`)
          .join(', ');
        
        // Envoyer a TOUS les appareils en un seul appel groupé
        if (await shouldSendNotification(user.id, 'notif_reminder_j1')) {
          const allTokens = tokensResult.rows.map(r => r.fcm_token);
          await sendNotificationToMultiple(
            allTokens,
            `Rappel : ${count} arrivee(s) demain`,
            propertiesList,
            { type: 'reminder_j1', count: count.toString() }
          );
        
        console.log(`Rappel J-1 envoye a user ${user.id} : ${count} arrivee(s) sur ${allTokens.length} appareil(s)`);
        } // end shouldSendNotification
      }
    }
    
    console.log('Rappels J-1 envoyes');
  } catch (error) {
    console.error('Erreur CRON rappels:', error);
  }
}, {
  timezone: "Europe/Paris"
});

console.log('CRON rappels J-1 configure (18h quotidien)');

// ============================================
// CRON : ALERTE MÉNAGE NON VALIDÉ — 1H AVANT ARRIVÉE
// ============================================
// Tourne toutes les 15 minutes
// Anti-doublon : stocke les réservations déjà alertées en mémoire
const _cleaningAlertSent = new Set();

cron.schedule('*/15 * * * *', async () => {
  try {
    const nowParis = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Paris' }));
    const in60min = new Date(nowParis.getTime() + 60 * 60 * 1000);
    const in75min = new Date(nowParis.getTime() + 75 * 60 * 1000); // fenêtre de 15 min

    // Format YYYY-MM-DD pour comparer les dates
    const todayStr = nowParis.toISOString().split('T')[0];

    // Récupère toutes les réservations dont l'arrivée est aujourd'hui
    // + le logement a une heure d'arrivée définie
    // + un ménage est assigné mais pas validé
    const result = await pool.query(`
      SELECT
        r.uid            AS reservation_uid,
        r.user_id,
        r.property_id,
        r.guest_name,
        r.start_date,
        p.name           AS property_name,
        p.internal_name  AS property_internal_name,
        p.arrival_time,
        cc.is_validated,
        cc.id            AS checklist_id
      FROM reservations r
      JOIN properties p ON p.id = r.property_id
      LEFT JOIN cleaning_checklists cc ON cc.reservation_key = r.uid AND cc.user_id = r.user_id
      WHERE
        DATE(r.start_date) = $1
        AND r.status NOT IN ('cancelled', 'completed')
        AND p.arrival_time IS NOT NULL
        AND p.arrival_time != ''
        AND cc.id IS NOT NULL
        AND (cc.is_validated = FALSE OR cc.is_validated IS NULL)
    `, [todayStr]);

    for (const row of result.rows) {
      // Reconstituer l'heure d'arrivée en heure Paris
      const [hours, minutes] = (row.arrival_time || '15:00').split(':').map(Number);
      const arrivalDateParis = new Date(nowParis);
      arrivalDateParis.setHours(hours, minutes || 0, 0, 0);

      // Vérifier si l'arrivée est dans la fenêtre [+60min, +75min]
      if (arrivalDateParis < in60min || arrivalDateParis > in75min) continue;

      // Anti-doublon
      const alertKey = `${row.reservation_uid}_cleaning_alert`;
      if (_cleaningAlertSent.has(alertKey)) continue;

      // Vérifier que l'hôte a activé cette notification
      const notifSettings = await getUserNotificationSettings(pool, row.user_id);
      if (!notifSettings.notif_cleaning_alert) continue;

      _cleaningAlertSent.add(alertKey);

      // Récupérer les tokens FCM de l'hôte
      const tokensResult = await pool.query(
        'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1 AND fcm_token IS NOT NULL',
        [row.user_id]
      );
      if (tokensResult.rows.length === 0) continue;

      const tokens = tokensResult.rows.map(r => r.fcm_token);
      const guestName = row.guest_name || 'Voyageur';
      const propName = row.property_internal_name?.trim() || row.property_name || 'Logement';
      const title = `⚠️ Ménage non validé — ${propName}`;
      const body = `${guestName} arrive dans moins d'1h et le ménage n'est pas encore validé.`;

      await sendNotificationToMultiple(tokens, title, body, {
        type: 'cleaning_alert',
        reservation_uid: row.reservation_uid,
        property_id: row.property_id
      });

      console.log(`🧹 Alerte ménage envoyée → ${propName} (${guestName})`);
    }
  } catch (err) {
    console.error('❌ CRON alerte ménage:', err.message);
  }
}, { timezone: 'Europe/Paris' });

console.log('CRON alerte ménage configuré (toutes les 15 min)');
// ============================================
// CHARGER LES RÉSERVATIONS MANUELLES DEPUIS LA DB
// ============================================
async function loadManualReservationsFromDB() {
  try {
    console.log('📦 Chargement des réservations manuelles depuis la DB...');
    
    const result = await pool.query(`
      SELECT * FROM reservations 
      WHERE source = 'MANUEL' 
      AND status != 'cancelled'
      ORDER BY start_date ASC
    `);
    
    // Reconstruire les objets réservation en mémoire
    for (const row of result.rows) {
      const reservation = {
        uid: row.uid,
        start: row.start_date,
        end: row.end_date,
        source: row.source,
        platform: row.platform,
        type: row.reservation_type,
        guestName: row.guest_name,
        notes: '',
        createdAt: row.created_at,
        propertyId: row.property_id,
        propertyName: '', // Sera rempli par la synchro
        propertyColor: '#3b82f6',
        userId: row.user_id,
        nights: Math.ceil((new Date(row.end_date) - new Date(row.start_date)) / (1000 * 60 * 60 * 24))
      };
      
      // Ajouter à MANUAL_RESERVATIONS
      if (!MANUAL_RESERVATIONS[row.property_id]) {
        MANUAL_RESERVATIONS[row.property_id] = [];
      }
      MANUAL_RESERVATIONS[row.property_id].push(reservation);
    }
    
    console.log(`✅ ${result.rows.length} réservations manuelles chargées depuis la DB`);
    
    // 📊 DEBUG : Afficher combien de réservations par propriété
    console.log('📊 Répartition par propriété:');
    for (const [propId, reservations] of Object.entries(MANUAL_RESERVATIONS)) {
      console.log(`  - ${propId}: ${reservations.length} réservations`);
    }
    
  } catch (error) {
    console.error('❌ Erreur chargement réservations manuelles:', error);
  }
}
// ============================================
// SUPPRESSION DE COMPTE
// ============================================
app.delete('/api/account/delete', authenticateToken, async (req, res) => {
  try {
    const userId = req.user.id;
    console.log(`🗑️ Suppression compte demandée par user ${userId}`);

    // Récupérer l'email avant suppression pour l'email de confirmation
    const userRow = await pool.query('SELECT email, first_name FROM users WHERE id = $1', [userId]);
    const userEmail = userRow.rows[0]?.email;
    const userName = userRow.rows[0]?.first_name || 'Utilisateur';

    await pool.query('DELETE FROM user_fcm_tokens WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM sub_account_permissions WHERE sub_account_id IN (SELECT id FROM sub_accounts WHERE parent_user_id = $1)', [userId]);
    await pool.query('DELETE FROM sub_account_properties WHERE sub_account_id IN (SELECT id FROM sub_accounts WHERE parent_user_id = $1)', [userId]);
    await pool.query('DELETE FROM sub_accounts WHERE parent_user_id = $1', [userId]);
    await pool.query('DELETE FROM cleaning_checklists WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM cleaners WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM deposits WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM payments WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM messages WHERE conversation_id IN (SELECT id FROM conversations WHERE user_id = $1)', [userId]);
    await pool.query('DELETE FROM conversations WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM reservations WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM properties WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM invoices WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM subscriptions WHERE user_id = $1', [userId]);
    await pool.query('DELETE FROM users WHERE id = $1', [userId]);

    console.log(`✅ Compte ${userId} supprimé`);

    // Envoyer email de confirmation de suppression
    if (userEmail) {
      try {
        await sendEmail({
          from: `Boostinghost <${process.env.EMAIL_FROM}>`,
          to: userEmail,
          subject: 'Votre compte Boostinghost a été supprimé',
          html: bhEmailTemplate({
            icon: '🗑️',
            title: 'Compte supprimé',
            tag: 'Confirmation de suppression',
            bodyHtml: `
              <p>Bonjour <strong>${userName}</strong>,</p>
              <p>Votre compte Boostinghost associé à l'adresse <strong>${userEmail}</strong> a bien été supprimé le ${new Date().toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', year: 'numeric' })}.</p>
              <p>Toutes vos données ont été définitivement effacées de nos serveurs conformément à votre demande.</p>
              <div class="danger-card">Si vous n'êtes pas à l'origine de cette action, contactez-nous immédiatement à <a href="mailto:support@boostinghost.fr" style="color:#1A7A5E;">support@boostinghost.fr</a>.</div>
            `,
            footerNote: 'Cet email confirme la suppression définitive de votre compte.'
          })
        });
        console.log(`📧 Email confirmation suppression envoyé à ${userEmail}`);
      } catch(emailErr) {
        console.warn('⚠️ Email confirmation suppression échoué:', emailErr.message);
      }
    }

    res.json({ success: true });
  } catch (err) {
    console.error('❌ Erreur suppression compte:', err);
    res.status(500).json({ error: 'Erreur lors de la suppression du compte' });
  }
});

// ============================================
// POST /api/contrat/send
// Génère un PDF de contrat de location et l'envoie par email
// ============================================
app.post('/api/contrat/send', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const {
      // Bailleur
      ownerFirstName, ownerLastName, ownerAddress, ownerEmail, ownerPhone,
      // Logement
      propertyName, propertyType, propertyAddress,
      // Dates
      checkin, checkout, checkinTime, checkoutTime, guestCount,
      // Locataire
      guestFirstName, guestLastName, guestEmail, guestPhone,
      guestNationality, guestAddress, guestDOB, guestIDNumber,
      // Finances
      totalPrice, cleaningFee, deposit, acompte, acompteDate, paymentMethod, priceNotes,
      // Règles
      regles,
      // Conditions légales
      inclAnnulation, cancelDays1, cancelPct1, cancelDays2, cancelPct2,
      inclObligations, obligationsExtra,
      inclAssurance,
      inclEDL, depositReturnDays,
      // Signature (base64 PNG)
      signatureData,
      // Date signature
      signatureDate,
      // Réservation liée (optionnel)
      reservationUid
    } = req.body;

    if (!guestEmail) return res.status(400).json({ error: 'Email du locataire requis' });
    if (!guestFirstName || !guestLastName) return res.status(400).json({ error: 'Nom du locataire requis' });

    // ── Calcul nuits ──
    const nights = checkin && checkout
      ? Math.round((new Date(checkout) - new Date(checkin)) / 86400000)
      : 0;

    const fmtDate = (d) => d ? new Date(d).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' }) : '—';
    const fmtDateShort = (d) => d ? new Date(d).toLocaleDateString('fr-FR') : '—';
    const payLabels = { virement: 'Virement bancaire', especes: 'Espèces', cheque: 'Chèque', carte: 'Carte bancaire', autre: 'Autre' };
    const propTypeLabels = { appartement: 'Appartement', maison: 'Maison', studio: 'Studio', villa: 'Villa', chambre: 'Chambre', gite: 'Gîte / Chalet', autre: 'Autre' };

    // ── Génération PDF avec PDFKit ──
    const contratNumber = `CONT-${Date.now()}`;
    const pdfPath = path.join(INVOICE_PDF_DIR, `${contratNumber}.pdf`);

    await new Promise((resolve, reject) => {
      const doc = new PDFDocument({ size: 'A4', margin: 50 });
      const stream = fs.createWriteStream(pdfPath);
      doc.pipe(stream);

      const green = '#1A7A5E';
      const dark = '#0D1117';
      const gray = '#7A8695';
      const lightBg = '#F5F2EC';
      const pageW = doc.page.width - 100; // content width with margins

      // ── HEADER ──
      doc.rect(0, 0, doc.page.width, 52).fill(green);
      doc.fillColor('white').fontSize(14).font('Helvetica-Bold')
        .text('BOOSTINGHOST', 50, 18);
      doc.fontSize(9).font('Helvetica')
        .text(`Généré le ${fmtDateShort(new Date())}`, 0, 22, { align: 'right', width: doc.page.width - 50 });

      let y = 75;

      // ── TITRE ──
      doc.fillColor(dark).fontSize(20).font('Helvetica-Bold')
        .text('Contrat de location meublée saisonnière', 50, y, { align: 'center', width: pageW });
      y += 35;
      doc.fillColor(gray).fontSize(9).font('Helvetica')
        .text(`Établi le ${fmtDate(signatureDate || new Date())}`, 50, y, { align: 'center', width: pageW });
      y += 25;

      // Helper : section title
      const sectionTitle = (title) => {
        doc.rect(50, y, pageW, 16).fill(lightBg);
        doc.fillColor(green).fontSize(8).font('Helvetica-Bold')
          .text(title.toUpperCase(), 54, y + 4);
        doc.fillColor(dark);
        y += 20;
      };

      // Helper : row
      const row = (label, value) => {
        if (!value || value === '—') return;
        doc.fillColor(gray).fontSize(9).font('Helvetica').text(label, 54, y);
        doc.fillColor(dark).font('Helvetica-Bold')
          .text(String(value), 220, y, { width: pageW - 170 });
        y += 14;
      };

      // Helper : paragraph
      const para = (text) => {
        doc.fillColor(dark).fontSize(8.5).font('Helvetica')
          .text(text, 54, y, { width: pageW - 8, lineGap: 2 });
        y += doc.heightOfString(text, { width: pageW - 8, lineGap: 2 }) + 6;
      };

      const checkPage = () => {
        if (y > 740) { doc.addPage(); y = 50; }
      };

      // ── 1. BAILLEUR ──
      sectionTitle('1. Bailleur');
      row('Nom', `${ownerFirstName || ''} ${ownerLastName || ''}`.trim());
      row('Adresse', ownerAddress);
      if (ownerEmail) row('Email', ownerEmail);
      if (ownerPhone) row('Téléphone', ownerPhone);
      y += 6; checkPage();

      // ── 2. LOCATAIRE ──
      sectionTitle('2. Locataire');
      row('Nom complet', `${guestFirstName} ${guestLastName}`);
      row('Email', guestEmail);
      if (guestPhone) row('Téléphone', guestPhone);
      if (guestNationality) row('Nationalité', guestNationality);
      if (guestAddress) row('Adresse', guestAddress);
      if (guestDOB) row('Date de naissance', fmtDateShort(guestDOB));
      if (guestIDNumber) row("Pièce d'identité", guestIDNumber);
      y += 6; checkPage();

      // ── 3. OBJET ──
      sectionTitle('3. Objet de la location');
      row('Logement', propertyName);
      if (propertyType) row('Type', propTypeLabels[propertyType] || propertyType);
      row('Adresse', propertyAddress);
      para('Cette location meublée saisonnière ne constitue pas la résidence principale du locataire.');
      y += 4; checkPage();

      // ── 4. DURÉE ──
      sectionTitle('4. Durée du séjour');
      row('Arrivée', `${fmtDate(checkin)} à ${checkinTime || '15:00'}`);
      row('Départ', `${fmtDate(checkout)} à ${checkoutTime || '11:00'}`);
      row('Durée', `${nights} nuit${nights > 1 ? 's' : ''}`);
      row('Occupants max.', `${guestCount || 1} personne${parseInt(guestCount) > 1 ? 's' : ''}`);
      y += 6; checkPage();

      // ── 5. CONDITIONS FINANCIÈRES ──
      sectionTitle('5. Conditions financières');
      row('Loyer total (CC)', `${parseFloat(totalPrice || 0).toFixed(2)} €`);
      if (cleaningFee && parseFloat(cleaningFee) > 0) row('Dont frais de ménage', `${parseFloat(cleaningFee).toFixed(2)} €`);
      if (deposit && parseFloat(deposit) > 0) row('Dépôt de garantie', `${parseFloat(deposit).toFixed(2)} €`);
      if (acompte && parseFloat(acompte) > 0) row('Acompte versé', `${parseFloat(acompte).toFixed(2)} €${acompteDate ? ' le ' + fmtDateShort(acompteDate) : ''}`);
      row('Mode de paiement', payLabels[paymentMethod] || paymentMethod || '—');
      if (priceNotes) row('Notes', priceNotes);
      y += 6; checkPage();

      // ── 6. RÈGLES ──
      if (regles && regles.length > 0) {
        sectionTitle('6. Règles du logement');
        regles.forEach(r => {
          doc.fillColor(dark).fontSize(9).font('Helvetica').text(`• ${r}`, 56, y);
          y += 13;
        });
        y += 4; checkPage();
      }

      // ── 7. OBLIGATIONS ──
      if (inclObligations) {
        checkPage(); sectionTitle('Obligations du locataire');
        let texteOblig = "Le locataire s'engage à occuper paisiblement les lieux, à respecter le voisinage, à ne pas sous-louer le logement (même à titre gratuit), et à ne pas organiser de fêtes ou rassemblements sans accord écrit préalable du bailleur. Le logement devra être rendu dans l'état où il a été remis.";
        if (obligationsExtra) texteOblig += ' ' + obligationsExtra;
        para(texteOblig);
        y += 4; checkPage();
      }

      // ── 8. ANNULATION ──
      if (inclAnnulation) {
        checkPage(); sectionTitle("Politique d'annulation");
        para(`Plus de ${cancelDays1 || 30} jours avant l'arrivée : remboursement de ${cancelPct1 || 50}% des sommes versées. Moins de ${cancelDays2 || 7} jours avant l'arrivée : remboursement de ${cancelPct2 || 0}% des sommes versées.`);
        y += 4; checkPage();
      }

      // ── 9. ASSURANCE ──
      if (inclAssurance) {
        checkPage(); sectionTitle('Assurance responsabilité civile');
        para("Le locataire déclare être couvert par une assurance responsabilité civile en cours de validité couvrant les dommages pouvant survenir pendant la durée de la location. Il s'engage à en fournir la preuve sur simple demande du bailleur.");
        y += 4; checkPage();
      }

      // ── 10. ÉTAT DES LIEUX ──
      if (inclEDL) {
        checkPage(); sectionTitle('État des lieux & restitution de la caution');
        para(`Un état des lieux contradictoire sera réalisé à l'entrée et au départ. La caution sera restituée dans un délai de ${depositReturnDays || 7} jours après le départ, sous réserve d'éventuelles retenues justifiées.`);
        y += 4; checkPage();
      }

      // ── LITIGES ──
      checkPage(); sectionTitle('Tribunaux compétents');
      para('Tout litige relatif au présent contrat sera soumis à la juridiction compétente du lieu de situation du logement.');
      y += 10; checkPage();

      // ── LIEU ET DATE ──
      doc.fillColor(gray).fontSize(9).font('Helvetica')
        .text(`Fait le ${fmtDateShort(signatureDate || new Date())}`, 50, y);
      y += 20; checkPage();

      // ── SIGNATURES ──
      const sigW = (pageW - 20) / 2;
      doc.fillColor(gray).fontSize(8).font('Helvetica')
        .text('Signature du bailleur', 50, y)
        .text('Signature du locataire', 50 + sigW + 20, y);
      y += 5;
      doc.fillColor(dark).fontSize(8).font('Helvetica-Bold')
        .text(`${ownerFirstName || ''} ${ownerLastName || ''}`.trim(), 50, y)
        .text(`${guestFirstName} ${guestLastName}`, 50 + sigW + 20, y);
      y += 5;

      // Signature image si fournie
      if (signatureData && signatureData.startsWith('data:image/png;base64,')) {
        try {
          const sigBuffer = Buffer.from(signatureData.replace('data:image/png;base64,', ''), 'base64');
          doc.image(sigBuffer, 50, y, { width: sigW, height: 35 });
        } catch(e) { /* ignore if image fails */ }
      }
      y += 40;

      // Lignes de signature
      doc.moveTo(50, y).lineTo(50 + sigW, y).strokeColor('#AAAAAA').stroke();
      doc.moveTo(50 + sigW + 20, y).lineTo(50 + pageW, y).strokeColor('#AAAAAA').stroke();

      // ── FOOTER ──
      doc.rect(0, doc.page.height - 28, doc.page.width, 28).fill(lightBg);
      doc.fillColor(gray).fontSize(7).font('Helvetica')
        .text('Contrat généré via Boostinghost — www.boostinghost.fr', 0, doc.page.height - 18, { align: 'center', width: doc.page.width });

      doc.end();
      stream.on('finish', resolve);
      stream.on('error', reject);
    });

    const pdfBuffer = fs.readFileSync(pdfPath);

    // ── Email au locataire ──
    const checkinFr = fmtDate(checkin);
    const checkoutFr = fmtDate(checkout);

    const emailHtml = bhEmailTemplate({
      icon: '📄',
      title: 'Contrat de location',
      subtitle: `${propertyName}${checkinFr !== '—' ? ' · du ' + checkinFr + ' au ' + checkoutFr : ''}`,
      bodyHtml: `
        <p>Bonjour <strong>${guestFirstName} ${guestLastName}</strong>,</p>
        <p>Veuillez trouver ci-joint votre contrat de location pour votre séjour à <strong>${propertyName}</strong>${checkinFr !== '—' ? ` du <strong>${checkinFr}</strong> au <strong>${checkoutFr}</strong>` : ''}.</p>
        <div style="background:#F5F2EC;border:1px solid #DDD8CE;border-radius:8px;padding:18px 20px;margin:20px 0;font-size:14px;">
          <table style="width:100%;border-collapse:collapse;">
            ${checkin && checkout ? `<tr><td style="padding:5px 0;color:#666;">Séjour</td><td style="padding:5px 0;font-weight:600;text-align:right;">${checkinFr} → ${checkoutFr}</td></tr>
            <tr><td style="padding:5px 0;color:#666;">Durée</td><td style="padding:5px 0;font-weight:600;text-align:right;">${nights} nuit${nights > 1 ? 's' : ''}</td></tr>` : ''}
            <tr><td style="padding:5px 0;color:#666;">Loyer total</td><td style="padding:5px 0;font-weight:700;color:#1A7A5E;text-align:right;">${parseFloat(totalPrice || 0).toFixed(2)} €</td></tr>
            ${deposit && parseFloat(deposit) > 0 ? `<tr><td style="padding:5px 0;color:#666;">Dépôt de garantie</td><td style="padding:5px 0;text-align:right;">${parseFloat(deposit).toFixed(2)} €</td></tr>` : ''}
          </table>
        </div>
        <div class="success-card">📎 Votre contrat PDF est joint à cet email.</div>
        <p style="font-size:14px;color:#666;">Pour toute question, n'hésitez pas à contacter le bailleur.<br>Cordialement, <strong>${[ownerFirstName, ownerLastName].filter(Boolean).join(' ')}</strong></p>
      `
    });

    const subject = `Contrat de location – ${propertyName}${checkin ? ' du ' + fmtDateShort(checkin) : ''}`;
    const attachment = [{ filename: `contrat_${guestLastName.toLowerCase()}_${checkin || 'date'}.pdf`, content: pdfBuffer, contentType: 'application/pdf' }];

    // Nettoyage PDF temporaire (on n'envoie plus le PDF à ce stade)
    try { fs.unlinkSync(pdfPath); } catch(e) {}

    const bailleurEmail = ownerEmail || (await getUserFromRequest(req))?.email;

    // ── Sauvegarder le contrat en base + générer token de signature ──
    let contractId = null;
    let signToken = null;
    try {
      contractId = 'cont_' + Date.now().toString(36) + crypto.randomBytes(4).toString('hex');
      signToken = crypto.randomBytes(32).toString('hex');
      const signExpires = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000); // 7 jours

      const contractData = {
        ownerFirstName, ownerLastName, ownerAddress, ownerEmail, ownerPhone,
        propertyName, propertyType, propertyAddress,
        checkin, checkout, checkinTime, checkoutTime, guestCount,
        guestFirstName, guestLastName, guestEmail, guestPhone,
        guestNationality, guestAddress, guestDOB, guestIDNumber,
        totalPrice, cleaningFee, deposit, acompte, acompteDate, paymentMethod, priceNotes,
        regles: regles || [],
        inclAnnulation, cancelDays1, cancelPct1, cancelDays2, cancelPct2,
        inclObligations, obligationsExtra,
        inclAssurance, inclEDL, depositReturnDays,
        signatureDate
      };

      await pool.query(`
        INSERT INTO contracts (id, user_id, reservation_uid, property_id, status, contract_data, owner_signature, sign_token, sign_token_expires_at, created_at, updated_at)
        VALUES ($1, $2, $3, $4, 'sent', $5, $6, $7, $8, NOW(), NOW())
      `, [
        contractId,
        userId,
        reservationUid || null,
        propertyAddress || null,
        JSON.stringify(contractData),
        signatureData || null,
        signToken,
        signExpires
      ]);

      // ── Envoyer l'email de signature au locataire ──
      const appUrl = (process.env.APP_URL || 'https://boostinghost.fr').replace(/\/$/, '');
      const signUrl = `${appUrl}/signer-contrat.html?token=${signToken}`;

      const signEmailHtml = bhEmailTemplate({
        icon: '✍️',
        title: 'Signature de votre contrat',
        subtitle: `${propertyName}${checkin ? ' · du ' + new Date(checkin).toLocaleDateString('fr-FR') : ''}`,
        bodyHtml: `
          <p>Bonjour <strong>${guestFirstName} ${guestLastName}</strong>,</p>
          <p>Votre contrat de location pour <strong>${propertyName}</strong> est prêt. Il ne reste plus qu'à le signer électroniquement.</p>
          <div class="cta-block">
            <p>Cliquez sur le bouton ci-dessous pour consulter et signer votre contrat :</p>
            <a href="${signUrl}" class="btn" style="display:inline-block;background:#1A7A5E;color:#fff;text-decoration:none;padding:14px 32px;border-radius:8px;font-size:15px;font-weight:700;">
              ✍️ Signer mon contrat
            </a>
          </div>
          <div class="alert-card">⏰ Ce lien est valable <strong>7 jours</strong>. Passé ce délai, contactez votre bailleur pour un nouveau lien.</div>
          <p style="font-size:13px;color:#666;">Si le bouton ne fonctionne pas, copiez ce lien dans votre navigateur :<br><a href="${signUrl}" style="color:#1A7A5E;word-break:break-all;">${signUrl}</a></p>
        `
      });

      await transporter.sendMail({
        from: process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>',
        to: guestEmail,
        subject: `Action requise : signez votre contrat – ${propertyName}`,
        html: signEmailHtml
      });

      console.log('✅ Email de signature envoyé à:', guestEmail);
    } catch (dbErr) {
      console.error('⚠️ Erreur sauvegarde contrat DB:', dbErr?.message);
      // On ne bloque pas la réponse si la DB échoue
    }

    res.json({
      success: true,
      message: `Lien de signature envoyé à ${guestEmail}`,
      contractId,
      signToken: signToken ? 'généré' : null
    });

  } catch (err) {
    console.error('❌ Erreur /api/contrat/send:', err);
    res.status(500).json({ error: err.message || 'Erreur serveur' });
  }
});

// ============================================
// GET /api/contrat/sign/:token  (PUBLIC — pas d'auth)
// Récupère les données du contrat pour la page de signature locataire
// ============================================
app.get('/api/contrat/sign/:token', async (req, res) => {
  try {
    const { token } = req.params;
    const result = await pool.query(
      `SELECT id, status, contract_data, owner_signature, sign_token_expires_at
       FROM contracts WHERE sign_token = $1`,
      [token]
    );
    if (!result.rows.length) return res.status(404).json({ error: 'Lien introuvable ou expiré' });

    const contract = result.rows[0];
    if (contract.status === 'signed') return res.status(400).json({ error: 'Ce contrat a déjà été signé', alreadySigned: true });
    if (new Date(contract.sign_token_expires_at) < new Date()) {
      await pool.query(`UPDATE contracts SET status = 'expired', updated_at = NOW() WHERE sign_token = $1`, [token]);
      return res.status(410).json({ error: 'Ce lien a expiré. Contactez votre bailleur pour un nouveau lien.' });
    }

    res.json({
      contractId: contract.id,
      contractData: contract.contract_data,
      ownerSignature: contract.owner_signature,
      expiresAt: contract.sign_token_expires_at
    });
  } catch (err) {
    console.error('❌ GET /api/contrat/sign/:token:', err);
    res.status(500).json({ error: err.message });
  }
});

// ============================================
// POST /api/contrat/sign/:token  (PUBLIC — locataire signe)
// ============================================
app.post('/api/contrat/sign/:token', async (req, res) => {
  try {
    const { token } = req.params;
    const { guestSignature } = req.body;
    if (!guestSignature) return res.status(400).json({ error: 'Signature manquante' });

    const result = await pool.query(
      `SELECT c.*, u.email as owner_email, u.first_name as owner_first_name
       FROM contracts c
       LEFT JOIN users u ON u.id = c.user_id
       WHERE c.sign_token = $1`,
      [token]
    );
    if (!result.rows.length) return res.status(404).json({ error: 'Lien introuvable' });

    const contract = result.rows[0];
    if (contract.status === 'signed') return res.status(400).json({ error: 'Déjà signé', alreadySigned: true });
    if (new Date(contract.sign_token_expires_at) < new Date()) return res.status(410).json({ error: 'Lien expiré' });

    const signIp = req.headers['x-forwarded-for']?.split(',')[0] || req.socket.remoteAddress;
    const signedAt = new Date();

    // Mettre à jour le contrat en DB
    await pool.query(`
      UPDATE contracts
      SET status = 'signed', guest_signature = $1, guest_signed_at = $2, guest_sign_ip = $3, updated_at = NOW()
      WHERE sign_token = $4
    `, [guestSignature, signedAt, signIp, token]);

    // Régénérer le PDF avec les 2 signatures
    const rawData = contract.contract_data;
    const data = typeof rawData === 'string' ? JSON.parse(rawData) : rawData;
    const isMandat = data.contractType === 'mandat';
    console.log(`🔍 Sign route — contractType: "${data.contractType}" — isMandat: ${isMandat}`);
    const nights = data.checkin && data.checkout
      ? Math.round((new Date(data.checkout) - new Date(data.checkin)) / 86400000) : 0;
    const fmtDate = (d) => d ? new Date(d).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' }) : '—';
    const fmtDateShort = (d) => d ? new Date(d).toLocaleDateString('fr-FR') : '—';

    const signedPdfPath = path.join(INVOICE_PDF_DIR, `contrat_signe_${contract.id}.pdf`);
    await new Promise((resolve, reject) => {
      const doc = new PDFDocument({ size: 'A4', margin: 50 });
      const stream = fs.createWriteStream(signedPdfPath);
      doc.pipe(stream);

      const green = '#1A7A5E', dark = '#0D1117', gray = '#7A8695', lightBg = '#F5F2EC';
      const pageW = doc.page.width - 100;

      doc.rect(0, 0, doc.page.width, 52).fill(green);
      doc.fillColor('white').fontSize(14).font('Helvetica-Bold').text(isMandat ? (data.companyName || 'BOOSTINGHOST') : 'BOOSTINGHOST', 50, 18);
      doc.fontSize(9).font('Helvetica').text(`Généré le ${fmtDateShort(new Date())}`, 0, 22, { align: 'right', width: doc.page.width - 50 });

      let y = 75;
      doc.fillColor(dark).fontSize(20).font('Helvetica-Bold').text(isMandat ? 'Contrat de mandat de gestion' : 'Contrat de location meublée saisonnière', 50, y, { align: 'center', width: pageW });
      y += 35;
      doc.fillColor(gray).fontSize(9).font('Helvetica').text(`Établi le ${fmtDate(data.signatureDate || new Date())} — Signé le ${fmtDate(signedAt)}`, 50, y, { align: 'center', width: pageW });
      y += 30;

      const sectionTitle = (title) => {
        doc.rect(50, y, pageW, 16).fill(lightBg);
        doc.fillColor(green).fontSize(8).font('Helvetica-Bold').text(title.toUpperCase(), 54, y + 4);
        doc.fillColor(dark); y += 20;
      };
      const row = (label, value) => {
        if (!value || value === '—') return;
        doc.fillColor(gray).fontSize(9).font('Helvetica').text(label, 54, y);
        doc.fillColor(dark).font('Helvetica-Bold').text(String(value), 220, y, { width: pageW - 170 });
        y += 14;
      };
      const para = (text) => {
        doc.fillColor(dark).fontSize(8.5).font('Helvetica').text(text, 54, y, { width: pageW - 8, lineGap: 2 });
        y += doc.heightOfString(text, { width: pageW - 8, lineGap: 2 }) + 6;
      };
      const checkPage = () => { if (y > 740) { doc.addPage(); y = 50; } };

      if (isMandat) {
        // ── CORPS MANDAT ──
        const propTypeLabels = { appartement: 'Appartement', maison: 'Maison', studio: 'Studio', villa: 'Villa', chambre: 'Chambre', gite: 'Gîte / Chalet', autre: 'Autre' };
        const remuLabels = {
          commission: `${data.commissionRate || '—'}% sur les revenus ${data.commissionBase === 'ttc' ? 'TTC' : 'HT'}`,
          forfait_mensuel: `${data.forfaitMensuel || '—'} €/mois`,
          forfait_resa: `${data.forfaitResa || '—'} €/réservation`,
          mixte: `${data.mixteRate || '—'}% + ${data.mixteForfait || '—'} €/mois`,
          carte: 'Prestations à la carte'
        };
        const exclusiviteLabels = { non: 'Sans exclusivité', totale: 'Exclusivité totale', partielle: 'Exclusivité partielle' };

        sectionTitle('1. Conciergerie / Prestataire');
        row('Raison sociale', data.companyName);
        if (data.companyLegal) row('Forme juridique', data.companyLegal);
        row('Siège social', data.companyAddress);
        if (data.companySiret) row('SIRET', data.companySiret);
        row('Représentée par', data.companyRep);
        if (data.companyEmail) row('Email', data.companyEmail);
        if (data.companyPhone) row('Téléphone', data.companyPhone);
        if (data.companyFreeTitle && data.companyFreeValue) row(data.companyFreeTitle, data.companyFreeValue);
        y += 6; checkPage();

        sectionTitle('2. Propriétaire / Mandant');
        row('Nom complet', `${data.ownerFirstName || ''} ${data.ownerLastName || ''}`.trim());
        if (data.ownerAddress) row('Adresse', data.ownerAddress);
        if (data.ownerEmail) row('Email', data.ownerEmail);
        if (data.ownerPhone) row('Téléphone', data.ownerPhone);
        if (data.ownerSiren) row('SIREN', data.ownerSiren);
        y += 6; checkPage();

        sectionTitle('3. Bien confié');
        row('Adresse', data.propAddress);
        if (data.propType) row('Type', propTypeLabels[data.propType] || data.propType);
        if (data.propCapacity) row('Capacité max.', `${data.propCapacity} personne${parseInt(data.propCapacity) > 1 ? 's' : ''}`);
        if (data.checkinTime) row("Heure d'arrivée", data.checkinTime);
        if (data.checkoutTime) row('Heure de départ', data.checkoutTime);
        y += 6; checkPage();

        if (data.missions && data.missions.length > 0) {
          sectionTitle('4. Missions confiées');
          data.missions.forEach(m => { doc.fillColor(dark).fontSize(9).font('Helvetica').text(`• ${m}`, 56, y, { width: pageW - 16 }); y += 13; });
          if (data.urgenceLimit) { y += 4; para(`Plafond dépenses urgentes : ${data.urgenceLimit} € TTC`); }
          y += 4; checkPage();
        }

        sectionTitle('5. Rémunération');
        row('Mode', remuLabels[data.remuType] || '—');
        if (data.tva === 'franchise') row('TVA', 'Auto-entrepreneur (sans TVA)');
        else if (data.tva === 'ht') row('TVA', 'HT — TVA en sus');
        else row('TVA', 'TTC');
        const revLabels = { par_resa: 'Par réservation', hebdo: 'Hebdomadaire', mensuel: 'Mensuel', encaissement_direct: 'Encaissement direct' };
        if (data.reversement) row('Reversements', revLabels[data.reversement] || data.reversement);
        if (data.extrasFacturables && data.extrasFacturables.length > 0) {
          y += 4;
          para('Prestations complémentaires : ' + data.extrasFacturables.join(', '));
        }
        y += 6; checkPage();

        sectionTitle('6. Durée & résiliation');
        row('Type', data.dureeType === 'determinee' ? `Durée déterminée — ${data.dureeMois || 12} mois` : 'Durée indéterminée');
        const dateDebut = data.dateDebut || data.dateDebutInd;
        if (dateDebut) row('Date de début', fmtDate(dateDebut));
        row('Préavis résiliation', data.preavis === '0' ? 'Aucun préavis' : `${data.preavis || 30} jours`);
        y += 6; checkPage();

        sectionTitle('7. Conditions générales');
        row('Exclusivité', exclusiviteLabels[data.exclusivite] || '—');
        row('Limitation de responsabilité', data.respPlafond === 'non' ? 'Responsabilité de droit commun' : 'Limitée aux honoraires perçus');
        if (data.confidentialite) row('Confidentialité', `${data.confidentialite} ans`);
        y += 4;
        para("La Conciergerie s'engage à exercer ses services avec diligence et professionnalisme. Elle ne peut être tenue responsable des dommages causés par des tiers ou des événements indépendants de sa volonté.");
        y += 4;
        para('La conciergerie ne garantit ni revenu minimal ni taux de réservation.');
        y += 6; checkPage();

        if (data.clausesPersonnalisees && data.clausesPersonnalisees.length > 0) {
          sectionTitle('8. Clauses particulières');
          data.clausesPersonnalisees.forEach((cl, i) => { para(`${i + 1}. ${cl}`); });
          y += 4; checkPage();
        }

        // Signatures mandat
        if (y > 660) { doc.addPage(); y = 50; }
        y += 10;
        doc.fillColor(gray).fontSize(9).font('Helvetica').text(`Fait le ${fmtDateShort(data.signatureDate || new Date())}`, 50, y);
        y += 20;
        const sigW = (pageW - 20) / 2;
        doc.fillColor(gray).fontSize(8).font('Helvetica')
          .text('Signature de la conciergerie', 50, y)
          .text('Signature du propriétaire', 50 + sigW + 20, y);
        y += 5;
        doc.fillColor(dark).fontSize(8).font('Helvetica-Bold')
          .text(data.companyRep || data.companyName || '', 50, y)
          .text(`${data.ownerFirstName || ''} ${data.ownerLastName || ''}`.trim(), 50 + sigW + 20, y);
        y += 5;
        if (contract.owner_signature && contract.owner_signature.startsWith('data:image/png;base64,')) {
          try { doc.image(Buffer.from(contract.owner_signature.replace('data:image/png;base64,', ''), 'base64'), 50, y, { width: sigW, height: 35 }); } catch(e) {}
        }
        if (guestSignature && guestSignature.startsWith('data:image/png;base64,')) {
          try { doc.image(Buffer.from(guestSignature.replace('data:image/png;base64,', ''), 'base64'), 50 + sigW + 20, y, { width: sigW, height: 35 }); } catch(e) {}
        }
        y += 42;
        doc.moveTo(50, y).lineTo(50 + sigW, y).strokeColor('#AAAAAA').stroke();
        doc.moveTo(50 + sigW + 20, y).lineTo(50 + pageW, y).strokeColor('#AAAAAA').stroke();
        y += 8;
        doc.fillColor(gray).fontSize(7).font('Helvetica')
          .text(`Conciergerie signée le ${fmtDateShort(data.signatureDate || new Date())}`, 50, y)
          .text(`Propriétaire signé le ${fmtDateShort(signedAt)} · IP: ${signIp}`, 50 + sigW + 20, y);

      } else {
        // ── CORPS LOCATION (inchangé) ──
        sectionTitle('1. Bailleur');
        row('Nom', `${data.ownerFirstName || ''} ${data.ownerLastName || ''}`.trim());
        row('Adresse', data.ownerAddress);
        if (data.ownerEmail) row('Email', data.ownerEmail);
        y += 6; checkPage();

        sectionTitle('2. Locataire');
        row('Nom complet', `${data.guestFirstName} ${data.guestLastName}`);
        row('Email', data.guestEmail);
        if (data.guestPhone) row('Téléphone', data.guestPhone);
        if (data.guestAddress) row('Adresse', data.guestAddress);
        y += 6; checkPage();

        sectionTitle('3. Objet de la location');
        row('Logement', data.propertyName);
        row('Adresse', data.propertyAddress);
        para('Cette location meublée saisonnière ne constitue pas la résidence principale du locataire.');
        y += 4; checkPage();

        sectionTitle('4. Durée du séjour');
        row('Arrivée', `${fmtDate(data.checkin)} à ${data.checkinTime || '15:00'}`);
        row('Départ', `${fmtDate(data.checkout)} à ${data.checkoutTime || '11:00'}`);
        row('Durée', `${nights} nuit${nights > 1 ? 's' : ''}`);
        y += 6; checkPage();

        sectionTitle('5. Conditions financières');
        row('Loyer total (CC)', `${parseFloat(data.totalPrice || 0).toFixed(2)} €`);
        if (data.deposit && parseFloat(data.deposit) > 0) row('Dépôt de garantie', `${parseFloat(data.deposit).toFixed(2)} €`);
        if (data.paymentMethod) row('Mode de paiement', data.paymentMethod);
        y += 6; checkPage();

        if (data.regles && data.regles.length > 0) {
          sectionTitle('6. Règles du logement');
          data.regles.forEach(r => { doc.fillColor(dark).fontSize(9).font('Helvetica').text(`• ${r}`, 56, y); y += 13; });
          y += 4; checkPage();
        }
        if (data.inclAnnulation) {
          checkPage(); sectionTitle("Politique d'annulation");
          para(`Plus de ${data.cancelDays1 || 30} jours avant l'arrivée : remboursement de ${data.cancelPct1 || 50}%. Moins de ${data.cancelDays2 || 7} jours : remboursement de ${data.cancelPct2 || 0}%.`);
          y += 4; checkPage();
        }
        if (data.inclObligations) {
          checkPage(); sectionTitle('Obligations du locataire');
          para("Le locataire s'engage à occuper paisiblement les lieux, à respecter le voisinage, à ne pas sous-louer le logement et à ne pas organiser de fêtes sans accord préalable du bailleur.");
          y += 4; checkPage();
        }
        if (data.inclAssurance) {
          checkPage(); sectionTitle('Assurance');
          para("Le locataire déclare être couvert par une assurance responsabilité civile.");
          y += 4; checkPage();
        }

        // Signatures location
        if (y > 680) { doc.addPage(); y = 50; }
        y += 10;
        doc.fillColor(gray).fontSize(9).font('Helvetica').text(`Fait le ${fmtDateShort(data.signatureDate || new Date())}`, 50, y);
        y += 20;
        const sigW = (pageW - 20) / 2;
        doc.fillColor(gray).fontSize(8).font('Helvetica')
          .text('Signature du bailleur', 50, y)
          .text('Signature du locataire', 50 + sigW + 20, y);
        y += 5;
        doc.fillColor(dark).fontSize(8).font('Helvetica-Bold')
          .text(`${data.ownerFirstName || ''} ${data.ownerLastName || ''}`.trim(), 50, y)
          .text(`${data.guestFirstName} ${data.guestLastName}`, 50 + sigW + 20, y);
        y += 5;
        if (contract.owner_signature && contract.owner_signature.startsWith('data:image/png;base64,')) {
          try { doc.image(Buffer.from(contract.owner_signature.replace('data:image/png;base64,', ''), 'base64'), 50, y, { width: sigW, height: 35 }); } catch(e) {}
        }
        if (guestSignature && guestSignature.startsWith('data:image/png;base64,')) {
          try { doc.image(Buffer.from(guestSignature.replace('data:image/png;base64,', ''), 'base64'), 50 + sigW + 20, y, { width: sigW, height: 35 }); } catch(e) {}
        }
        y += 42;
        doc.moveTo(50, y).lineTo(50 + sigW, y).strokeColor('#AAAAAA').stroke();
        doc.moveTo(50 + sigW + 20, y).lineTo(50 + pageW, y).strokeColor('#AAAAAA').stroke();
        y += 8;
        doc.fillColor(gray).fontSize(7).font('Helvetica')
          .text(`Bailleur signé le ${fmtDateShort(data.signatureDate || new Date())}`, 50, y)
          .text(`Locataire signé le ${fmtDateShort(signedAt)} · IP: ${signIp}`, 50 + sigW + 20, y);
      }

      doc.rect(0, doc.page.height - 28, doc.page.width, 28).fill(lightBg);
      doc.fillColor(gray).fontSize(7).font('Helvetica')
        .text('Contrat généré via Boostinghost — www.boostinghost.fr', 0, doc.page.height - 18, { align: 'center', width: doc.page.width });

      doc.end();
      stream.on('finish', resolve);
      stream.on('error', reject);
    });

    // Sauvegarder le chemin du PDF signé
    await pool.query(`UPDATE contracts SET signed_pdf_path = $1, updated_at = NOW() WHERE id = $2`, [signedPdfPath, contract.id]);

    // ── Notification push au propriétaire du compte ──
    try {
      const tokensRes = await pool.query(
        'SELECT fcm_token FROM user_fcm_tokens WHERE user_id = $1',
        [contract.user_id]
      );
      const signerName = isMandat
        ? `${data.ownerFirstName || ''} ${data.ownerLastName || ''}`.trim()
        : `${data.guestFirstName || ''} ${data.guestLastName || ''}`.trim();
      const docLabel = isMandat
        ? `Mandat – ${data.propAddress || data.companyName || ''}`
        : `Contrat – ${data.propertyName || ''}`;
      for (const tok of tokensRes.rows) {
        await sendNotification(
          tok.fcm_token,
          `✍️ ${isMandat ? 'Mandat' : 'Contrat'} signé`,
          `${signerName} a signé · ${docLabel}`,
          { type: 'contract_signed', contractId: String(contract.id) }
        );
      }
    } catch(nErr) { console.error('❌ Notif contrat signé:', nErr.message); }

    // Champs selon type (location vs mandat)
    const signerFirstName = isMandat ? data.ownerFirstName : data.guestFirstName;
    const signerLastName  = isMandat ? data.ownerLastName  : data.guestLastName;
    const signerEmail     = isMandat ? data.ownerEmail     : data.guestEmail;
    const senderEmail     = isMandat ? (data.companyEmail || contract.owner_email) : (data.ownerEmail || contract.owner_email);
    const docLabel        = isMandat ? `Mandat – ${data.propAddress || data.companyName || ''}` : `${data.propertyName || ''}`;

    // Envoyer le PDF signé aux 2 parties
    const pdfBuffer = fs.readFileSync(signedPdfPath);
    const attachment = [{
      filename: isMandat ? `mandat_signe_${signerLastName?.toLowerCase() || 'gestion'}.pdf` : `contrat_signe_${signerLastName?.toLowerCase() || 'location'}.pdf`,
      content: pdfBuffer, contentType: 'application/pdf'
    }];

    const signedEmailHtml = bhEmailTemplate({
      icon: '✅',
      title: isMandat ? 'Mandat de gestion signé' : 'Contrat signé',
      subtitle: docLabel,
      bodyHtml: `
        <p>${isMandat ? 'Le mandat de gestion' : 'Le contrat de location'} a été signé par les deux parties.</p>
        <div class="success-card">📎 Le document signé est joint à cet email.</div>
        <div class="info-card">
          <strong>${isMandat ? 'Propriétaire' : 'Locataire'} :</strong> ${signerFirstName} ${signerLastName}<br>
          <strong>Signé le :</strong> ${fmtDate(signedAt)}<br>
          ${isMandat ? `<strong>Bien confié :</strong> ${data.propAddress || '—'}` : `<strong>Logement :</strong> ${data.propertyName}`}
        </div>
      `
    });

    // Email au signataire
    try {
      await transporter.sendMail({
        from: process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>',
        to: signerEmail,
        subject: `${isMandat ? 'Mandat' : 'Contrat'} signé – ${isMandat ? data.companyName : data.propertyName}`,
        html: signedEmailHtml, attachments: attachment
      });
    } catch(e) { console.error('⚠️ Email signataire PDF signé:', e.message); }

    // Email à l'autre partie
    if (senderEmail && senderEmail !== signerEmail) {
      try {
        await transporter.sendMail({
          from: process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>',
          to: senderEmail,
          subject: `[Signé] ${isMandat ? 'Mandat' : 'Contrat'} – ${signerFirstName} ${signerLastName}`,
          html: signedEmailHtml, attachments: attachment
        });
      } catch(e) { console.error('⚠️ Email autre partie PDF signé:', e.message); }
    }

    try { fs.unlinkSync(signedPdfPath); } catch(e) {}

    console.log(`✅ Contrat ${contract.id} signé par ${signerFirstName} ${signerLastName}`);
    res.json({ success: true, message: `${isMandat ? 'Mandat' : 'Contrat'} signé avec succès. Le PDF vous a été envoyé par email.` });

  } catch (err) {
    console.error('❌ POST /api/contrat/sign/:token:', err);
    res.status(500).json({ error: err.message });
  }
});

// ============================================
// GET /api/contrats  — Historique des contrats (authentifié)
// ============================================
app.get('/api/contrats', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const { status, limit = 50, offset = 0 } = req.query;
    let query = `SELECT id, status, reservation_uid, sign_token_expires_at, guest_signed_at, created_at,
                        contract_data,
                        contract_data->>'guestFirstName' as guest_first_name,
                        contract_data->>'guestLastName' as guest_last_name,
                        contract_data->>'guestEmail' as guest_email,
                        contract_data->>'propertyName' as property_name,
                        contract_data->>'checkin' as checkin,
                        contract_data->>'checkout' as checkout,
                        contract_data->>'totalPrice' as total_price
                 FROM contracts WHERE user_id = $1`;
    const params = [userId];

    if (status) { query += ` AND status = $${params.length + 1}`; params.push(status); }
    query += ` ORDER BY created_at DESC LIMIT $${params.length + 1} OFFSET $${params.length + 2}`;
    params.push(parseInt(limit), parseInt(offset));

    const result = await pool.query(query, params);
    const countResult = await pool.query(`SELECT COUNT(*) FROM contracts WHERE user_id = $1${status ? ' AND status = $2' : ''}`, status ? [userId, status] : [userId]);

    res.json({
      contracts: result.rows,
      total: parseInt(countResult.rows[0].count),
      limit: parseInt(limit),
      offset: parseInt(offset)
    });
  } catch (err) {
    console.error('❌ GET /api/contrats:', err);
    res.status(500).json({ error: err.message });
  }
});

// ============================================
// GET /api/contrats/:id  — Détail d'un contrat
// ============================================
app.get('/api/contrats/:id', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const result = await pool.query(
      `SELECT * FROM contracts WHERE id = $1 AND user_id = $2`,
      [req.params.id, userId]
    );
    if (!result.rows.length) return res.status(404).json({ error: 'Contrat introuvable' });

    res.json(result.rows[0]);
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

// ============================================
// POST /api/contrats/:id/resend-sign
// Renouvelle le token de signature et renvoie l'email au locataire
// ============================================
app.post('/api/contrats/:id/resend-sign', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const result = await pool.query(
      `SELECT * FROM contracts WHERE id = $1 AND user_id = $2`,
      [req.params.id, userId]
    );
    if (!result.rows.length) return res.status(404).json({ error: 'Contrat introuvable' });

    const contract = result.rows[0];
    if (contract.status === 'signed') {
      return res.status(400).json({ error: 'Ce contrat est déjà signé.' });
    }

    // Générer un nouveau token (7 jours)
    const newToken = crypto.randomBytes(32).toString('hex');
    const newExpires = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);

    await pool.query(
      `UPDATE contracts SET sign_token = $1, sign_token_expires_at = $2, status = 'sent', updated_at = NOW() WHERE id = $3`,
      [newToken, newExpires, contract.id]
    );

    const d = typeof contract.contract_data === 'string' ? JSON.parse(contract.contract_data) : contract.contract_data;
    const isMandat = d.contractType === 'mandat';
    const recipientFirstName = isMandat ? d.ownerFirstName : d.guestFirstName;
    const recipientLastName = isMandat ? d.ownerLastName : d.guestLastName;
    const recipientEmail = isMandat ? d.ownerEmail : d.guestEmail;
    const subjectLabel = isMandat ? `Mandat de gestion – ${d.companyName || 'votre conciergerie'}` : `${d.propertyName || ''}`;

    const appUrl = (process.env.APP_URL || 'https://boostinghost.fr').replace(/\/$/, '');
    const signUrl = `${appUrl}/signer-contrat.html?token=${newToken}`;

    const signEmailHtml = bhEmailTemplate({
      icon: '✍️',
      title: 'Nouveau lien de signature',
      subtitle: subjectLabel,
      bodyHtml: `
        <p>Bonjour <strong>${recipientFirstName} ${recipientLastName}</strong>,</p>
        <p>Un nouveau lien de signature vous a été envoyé pour ${isMandat ? 'votre mandat de gestion' : `votre contrat de location à <strong>${d.propertyName}</strong>`}.</p>
        <div class="cta-block">
          <p>Cliquez ci-dessous pour signer votre contrat :</p>
          <a href="${signUrl}" class="btn" style="display:inline-block;background:#1A7A5E;color:#fff;text-decoration:none;padding:14px 32px;border-radius:8px;font-size:15px;font-weight:700;">
            ✍️ Signer mon contrat
          </a>
        </div>
        <div class="alert-card">⏰ Ce lien est valable <strong>7 jours</strong>.</div>
        <p style="font-size:13px;color:#666;">Lien direct : <a href="${signUrl}" style="color:#1A7A5E;word-break:break-all;">${signUrl}</a></p>
      `
    });

    await transporter.sendMail({
      from: process.env.EMAIL_FROM || 'Boostinghost <no-reply@boostinghost.fr>',
      to: recipientEmail || d.guestEmail,
      subject: `Nouveau lien de signature – ${subjectLabel}`,
      html: signEmailHtml
    });

    console.log(`✅ Lien signature renvoyé pour contrat ${contract.id} à ${recipientEmail || d.guestEmail}`);
    res.json({ success: true, message: `Lien de signature renvoyé à ${recipientEmail || d.guestEmail}` });

  } catch (err) {
    console.error('❌ POST /api/contrats/:id/resend-sign:', err);
    res.status(500).json({ error: err.message });
  }
});

// ============================================
// GET /api/contrats/:id/pdf
// Retourne le PDF signé en base64 pour téléchargement
// ============================================
app.get('/api/contrats/:id/pdf', authenticateAny, async (req, res) => {
  try {
    const userId = req.user.isSubAccount
      ? (await getRealUserId(pool, req))
      : (await getUserFromRequest(req))?.id;
    if (!userId) return res.status(401).json({ error: 'Non autorisé' });

    const result = await pool.query(
      `SELECT * FROM contracts WHERE id = $1 AND user_id = $2`,
      [req.params.id, userId]
    );
    if (!result.rows.length) return res.status(404).json({ error: 'Contrat introuvable' });

    const contract = result.rows[0];
    const d = typeof contract.contract_data === 'string' ? JSON.parse(contract.contract_data) : contract.contract_data;
    const isMandat = d.contractType === 'mandat';

    // Régénérer le PDF (signé si disponible, sinon avec seulement signature bailleur)
    const pdfPath = path.join(INVOICE_PDF_DIR, `contrat_dl_${contract.id}.pdf`);
    const isSigned = contract.status === 'signed';

    const fmtDate = (dt) => dt ? new Date(dt).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' }) : '—';
    const fmtDateShort = (dt) => dt ? new Date(dt).toLocaleDateString('fr-FR') : '—';

    // ── Rediriger vers PDF mandat si contractType === 'mandat' ──
    if (isMandat) {
      // Réutiliser la même logique de génération que /api/mandat/send
      const propTypeLabels = { appartement: 'Appartement', maison: 'Maison', studio: 'Studio', villa: 'Villa', chambre: 'Chambre', gite: 'Gîte / Chalet', autre: 'Autre' };
      const remuLabels = {
        commission: `${d.commissionRate || '—'}% sur les revenus ${d.commissionBase === 'ttc' ? 'TTC' : 'HT'}`,
        forfait_mensuel: `Forfait mensuel : ${d.forfaitMensuel || '—'} €`,
        forfait_resa: `Forfait par réservation : ${d.forfaitResa || '—'} €`,
        mixte: `${d.mixteRate || '—'}% + ${d.mixteForfait || '—'} €/mois`,
        carte: 'Prestations à la carte'
      };
      const tvaLabels = { ht: 'HT — TVA en sus', ttc: 'TTC', franchise: 'Auto-entrepreneur (sans TVA)' };
      const reversementLabels = { par_resa: 'À chaque réservation', hebdo: 'Hebdomadaire', mensuel: 'Mensuel', encaissement_direct: 'Encaissement direct' };
      const exclusiviteLabels = { non: 'Sans exclusivité', totale: 'Exclusivité totale', partielle: 'Exclusivité partielle' };

      await new Promise((resolve, reject) => {
        const doc = new PDFDocument({ size: 'A4', margin: 50 });
        const stream = fs.createWriteStream(pdfPath);
        doc.pipe(stream);

        const green = '#1A7A5E', dark = '#0D1117', gray = '#7A8695', lightBg = '#F5F2EC';
        const pageW = doc.page.width - 100;

        doc.rect(0, 0, doc.page.width, 52).fill(green);
        doc.fillColor('white').fontSize(14).font('Helvetica-Bold').text(d.companyName || 'BOOSTINGHOST', 50, 18);
        doc.fontSize(9).font('Helvetica').text(`Généré le ${fmtDateShort(new Date())}`, 0, 22, { align: 'right', width: doc.page.width - 50 });
        if (isSigned) doc.fontSize(8).font('Helvetica-Bold').fillColor('#4ADE80').text('✓ MANDAT SIGNÉ', 0, 30, { align: 'right', width: doc.page.width - 50 });

        let y = 75;
        doc.fillColor(dark).fontSize(20).font('Helvetica-Bold').text('Contrat de mandat de gestion', 50, y, { align: 'center', width: pageW });
        y += 28;
        doc.fillColor(gray).fontSize(9).font('Helvetica').text('Location saisonnière / courte durée', 50, y, { align: 'center', width: pageW });
        y += 28;

        const sT = (title) => { if (y > 720) { doc.addPage(); y = 50; } doc.rect(50, y, pageW, 18).fill(lightBg); doc.fillColor(green).fontSize(8).font('Helvetica-Bold').text(title.toUpperCase(), 54, y + 5); doc.fillColor(dark); y += 23; };
        const row = (label, value) => { if (!value || value === '—') return; if (y > 750) { doc.addPage(); y = 50; } doc.fillColor(gray).fontSize(9).font('Helvetica').text(label, 54, y, { width: 160 }); doc.fillColor(dark).font('Helvetica-Bold').text(String(value), 220, y, { width: pageW - 170 }); y += 14; };
        const para = (text) => { if (y > 720) { doc.addPage(); y = 50; } doc.fillColor(dark).fontSize(8.5).font('Helvetica').text(text, 54, y, { width: pageW - 8, lineGap: 2 }); y += doc.heightOfString(text, { width: pageW - 8, lineGap: 2 }) + 6; };
        const bullet = (text) => { if (y > 750) { doc.addPage(); y = 50; } doc.fillColor(dark).fontSize(9).font('Helvetica').text(`• ${text}`, 60, y, { width: pageW - 16 }); y += 13; };

        sT('Article 1 — Parties');
        row('Conciergerie', d.companyName || '—');
        if (d.companyLegal) row('Forme juridique', d.companyLegal);
        if (d.companyAddress) row('Siège social', d.companyAddress);
        if (d.companySiret) row('SIRET', d.companySiret);
        if (d.companyRep) row('Représentée par', d.companyRep);
        if (d.companyEmail) row('Email', d.companyEmail);
        y += 6;
        row('Propriétaire', `${d.ownerFirstName} ${d.ownerLastName}`);
        if (d.ownerAddress) row('Adresse', d.ownerAddress);
        if (d.ownerEmail) row('Email', d.ownerEmail);
        if (d.ownerPhone) row('Téléphone', d.ownerPhone);
        y += 6;

        sT('Article 2 — Bien confié');
        row('Adresse', d.propAddress || '—');
        if (d.propType) row('Type', propTypeLabels[d.propType] || d.propType);
        if (d.propCapacity) row('Capacité', `${d.propCapacity} personnes`);
        y += 6;

        if (d.missions && d.missions.length > 0) {
          sT('Article 3 — Missions confiées');
          d.missions.forEach(m => bullet(m));
          if (d.urgenceLimit) { y += 4; para(`Plafond dépenses urgentes : ${d.urgenceLimit} € TTC.`); }
          y += 6;
        }

        sT('Article 4 — Exclusions'); para('Sont exclues : gros travaux, sinistres en qualité d\'assuré, représentation en justice, obligations fiscales du propriétaire, garantie de revenu ou d\'occupation.'); y += 6;

        sT('Article 5 — Rémunération');
        row('Mode', remuLabels[d.remuType] || '—');
        row('TVA', tvaLabels[d.tva] || '—');
        row('Préavis révision', `${d.tarifPreavis || 60} jours`);
        row('Reversements', reversementLabels[d.reversement] || '—');
        if (d.extrasFacturables && d.extrasFacturables.length > 0) { y += 4; para('Prestations complémentaires :'); d.extrasFacturables.forEach(e => bullet(e)); }
        y += 6;

        sT('Article 6 — Durée et résiliation');
        row('Type', d.dureeType === 'determinee' ? `Durée déterminée — ${d.dureeMois || 12} mois` : 'Durée indéterminée');
        if (d.dateDebut) row('Début', fmtDate(d.dateDebut));
        row('Préavis résiliation', d.preavis === '0' ? 'Aucun préavis' : `${d.preavis || 30} jours`);
        y += 6;

        sT('Article 7 — Conditions générales');
        row('Exclusivité', exclusiviteLabels[d.exclusivite] || '—');
        row('Plafond responsabilité', d.respPlafond === '3mois' ? '3 mois d\'honoraires' : '12 mois d\'honoraires');
        row('Confidentialité', `${d.confidentialite || 5} ans après fin de contrat`);
        y += 4;
        para('La conciergerie n\'est tenue que d\'une obligation de moyens et ne garantit ni revenu minimal ni taux de réservation.');
        y += 6;

        sT('Article 8 — Obligations des parties');
        para('La Conciergerie s\'engage à exécuter ses prestations avec diligence et à informer le propriétaire des incidents significatifs. Le Propriétaire s\'engage à délivrer un logement conforme et à régler les factures dans les délais.');
        y += 6;

        if (d.clausesPersonnalisees && d.clausesPersonnalisees.length > 0) {
          sT('Article 9 — Clauses particulières');
          d.clausesPersonnalisees.forEach((c, i) => para(`${i + 1}. ${c}`));
          y += 6;
        }

        // Signatures
        if (y > 680) { doc.addPage(); y = 50; }
        y += 10;
        doc.fillColor(gray).fontSize(9).font('Helvetica').text(`Fait le ${fmtDateShort(d.signatureDate || new Date())}`, 50, y);
        y += 20;

        const sigW = (pageW - 20) / 2;
        doc.fillColor(gray).fontSize(8).font('Helvetica').text('La Conciergerie / Prestataire', 50, y).text('Le Propriétaire / Mandant', 50 + sigW + 20, y);
        y += 5;
        doc.fillColor(dark).fontSize(8).font('Helvetica-Bold').text(d.companyRep || d.companyName || '—', 50, y).text(`${d.ownerFirstName} ${d.ownerLastName}`, 50 + sigW + 20, y);
        y += 5;

        if (contract.owner_signature?.startsWith('data:image/png;base64,')) {
          try { doc.image(Buffer.from(contract.owner_signature.replace('data:image/png;base64,', ''), 'base64'), 50, y, { width: sigW, height: 35 }); } catch(e) {}
        }
        if (isSigned && contract.guest_signature?.startsWith('data:image/png;base64,')) {
          try { doc.image(Buffer.from(contract.guest_signature.replace('data:image/png;base64,', ''), 'base64'), 50 + sigW + 20, y, { width: sigW, height: 35 }); } catch(e) {}
        } else if (!isSigned) {
          doc.fillColor(gray).fontSize(9).font('Helvetica').text('En attente de signature...', 50 + sigW + 20, y + 10);
        }
        y += 42;
        doc.moveTo(50, y).lineTo(50 + sigW, y).strokeColor('#AAAAAA').stroke();
        doc.moveTo(50 + sigW + 20, y).lineTo(50 + pageW, y).strokeColor('#AAAAAA').stroke();
        if (isSigned) { y += 8; doc.fillColor(gray).fontSize(7).font('Helvetica').text(`Signé le ${fmtDateShort(contract.guest_signed_at)} · IP: ${contract.guest_sign_ip || '—'}`, 50 + sigW + 20, y); }

        doc.rect(0, doc.page.height - 28, doc.page.width, 28).fill(lightBg);
        doc.fillColor(gray).fontSize(7).font('Helvetica').text('Contrat généré via Boostinghost — www.boostinghost.fr', 0, doc.page.height - 18, { align: 'center', width: doc.page.width });

        doc.end();
        stream.on('finish', resolve);
        stream.on('error', reject);
      });

      const pdfBuffer = fs.readFileSync(pdfPath);
      try { fs.unlinkSync(pdfPath); } catch(e) {}
      const filename = `mandat_${isSigned ? 'signe_' : ''}${d.ownerLastName?.toLowerCase() || 'gestion'}.pdf`;
      res.set('Content-Type', 'application/pdf');
      res.set('Content-Disposition', `attachment; filename="${filename}"`);
      return res.send(pdfBuffer);
    }

    const nights = d.checkin && d.checkout ? Math.round((new Date(d.checkout) - new Date(d.checkin)) / 86400000) : 0;

    await new Promise((resolve, reject) => {
      const doc = new PDFDocument({ size: 'A4', margin: 50 });
      const stream = fs.createWriteStream(pdfPath);
      doc.pipe(stream);

      const green = '#1A7A5E', dark = '#0D1117', gray = '#7A8695', lightBg = '#F5F2EC';
      const pageW = doc.page.width - 100;

      doc.rect(0, 0, doc.page.width, 52).fill(green);
      doc.fillColor('white').fontSize(14).font('Helvetica-Bold').text('BOOSTINGHOST', 50, 18);
      doc.fontSize(9).font('Helvetica').text(`Généré le ${fmtDateShort(new Date())}`, 0, 22, { align: 'right', width: doc.page.width - 50 });
      if (isSigned) {
        doc.fontSize(8).font('Helvetica-Bold').fillColor('#4ADE80')
          .text('✓ CONTRAT SIGNÉ', 0, 30, { align: 'right', width: doc.page.width - 50 });
      }

      let y = 75;
      doc.fillColor(dark).fontSize(20).font('Helvetica-Bold')
        .text('Contrat de location meublée saisonnière', 50, y, { align: 'center', width: pageW });
      y += 35;
      doc.fillColor(gray).fontSize(9).font('Helvetica')
        .text(`Établi le ${fmtDate(d.signatureDate || new Date())}${isSigned ? ` — Signé le ${fmtDate(contract.guest_signed_at)}` : ''}`, 50, y, { align: 'center', width: pageW });
      y += 28;

      const sectionTitle = (title) => {
        doc.rect(50, y, pageW, 16).fill(lightBg);
        doc.fillColor(green).fontSize(8).font('Helvetica-Bold').text(title.toUpperCase(), 54, y + 4);
        doc.fillColor(dark); y += 20;
      };
      const row = (label, value) => {
        if (!value || value === '—') return;
        doc.fillColor(gray).fontSize(9).font('Helvetica').text(label, 54, y);
        doc.fillColor(dark).font('Helvetica-Bold').text(String(value), 220, y, { width: pageW - 170 });
        y += 14;
      };
      const para = (text) => {
        doc.fillColor(dark).fontSize(8.5).font('Helvetica').text(text, 54, y, { width: pageW - 8, lineGap: 2 });
        y += doc.heightOfString(text, { width: pageW - 8, lineGap: 2 }) + 6;
      };
      const checkPage = () => { if (y > 740) { doc.addPage(); y = 50; } };

      sectionTitle('1. Bailleur');
      row('Nom', `${d.ownerFirstName || ''} ${d.ownerLastName || ''}`.trim());
      row('Adresse', d.ownerAddress);
      if (d.ownerEmail) row('Email', d.ownerEmail);
      y += 6; checkPage();

      sectionTitle('2. Locataire');
      row('Nom complet', `${d.guestFirstName} ${d.guestLastName}`);
      row('Email', d.guestEmail);
      if (d.guestPhone) row('Téléphone', d.guestPhone);
      if (d.guestAddress) row('Adresse', d.guestAddress);
      y += 6; checkPage();

      sectionTitle('3. Logement & durée');
      row('Logement', d.propertyName);
      row('Adresse', d.propertyAddress);
      row('Arrivée', `${fmtDate(d.checkin)} à ${d.checkinTime || '15:00'}`);
      row('Départ', `${fmtDate(d.checkout)} à ${d.checkoutTime || '11:00'}`);
      row('Durée', `${nights} nuit${nights > 1 ? 's' : ''}`);
      para('Location meublée saisonnière ne constituant pas la résidence principale du locataire.');
      y += 4; checkPage();

      sectionTitle('4. Conditions financières');
      row('Loyer total (CC)', `${parseFloat(d.totalPrice || 0).toFixed(2)} €`);
      if (d.deposit && parseFloat(d.deposit) > 0) row('Dépôt de garantie', `${parseFloat(d.deposit).toFixed(2)} €`);
      if (d.paymentMethod) row('Mode de paiement', d.paymentMethod);
      y += 6; checkPage();

      if (d.regles && d.regles.length > 0) {
        sectionTitle('5. Règles du logement');
        d.regles.forEach(r => { doc.fillColor(dark).fontSize(9).font('Helvetica').text(`• ${r}`, 56, y); y += 13; });
        y += 4; checkPage();
      }

      if (d.inclAnnulation) { checkPage(); sectionTitle("Politique d'annulation"); para(`Plus de ${d.cancelDays1 || 30} jours : ${d.cancelPct1 || 50}% remboursé. Moins de ${d.cancelDays2 || 7} jours : ${d.cancelPct2 || 0}% remboursé.`); y += 4; checkPage(); }
      if (d.inclObligations) { checkPage(); sectionTitle('Obligations'); para("Le locataire s'engage à occuper paisiblement les lieux et à ne pas sous-louer."); y += 4; checkPage(); }
      if (d.inclAssurance) { checkPage(); sectionTitle('Assurance'); para("Le locataire déclare être couvert par une assurance RC."); y += 4; checkPage(); }

      // Signatures
      if (y > 680) { doc.addPage(); y = 50; }
      y += 10;
      doc.fillColor(gray).fontSize(9).font('Helvetica').text(`Fait le ${fmtDateShort(d.signatureDate || new Date())}`, 50, y);
      y += 20;

      const sigW = (pageW - 20) / 2;
      doc.fillColor(gray).fontSize(8).font('Helvetica')
        .text('Signature du bailleur', 50, y)
        .text('Signature du locataire', 50 + sigW + 20, y);
      y += 5;
      doc.fillColor(dark).fontSize(8).font('Helvetica-Bold')
        .text(`${d.ownerFirstName || ''} ${d.ownerLastName || ''}`.trim(), 50, y)
        .text(`${d.guestFirstName} ${d.guestLastName}`, 50 + sigW + 20, y);
      y += 5;

      if (contract.owner_signature?.startsWith('data:image/png;base64,')) {
        try { doc.image(Buffer.from(contract.owner_signature.replace('data:image/png;base64,', ''), 'base64'), 50, y, { width: sigW, height: 35 }); } catch(e) {}
      }
      if (isSigned && contract.guest_signature?.startsWith('data:image/png;base64,')) {
        try { doc.image(Buffer.from(contract.guest_signature.replace('data:image/png;base64,', ''), 'base64'), 50 + sigW + 20, y, { width: sigW, height: 35 }); } catch(e) {}
      } else if (!isSigned) {
        doc.fillColor(gray).fontSize(9).font('Helvetica').text('En attente de signature...', 50 + sigW + 20, y + 10);
      }
      y += 42;
      doc.moveTo(50, y).lineTo(50 + sigW, y).strokeColor('#AAAAAA').stroke();
      doc.moveTo(50 + sigW + 20, y).lineTo(50 + pageW, y).strokeColor('#AAAAAA').stroke();

      if (isSigned) {
        y += 8;
        doc.fillColor(gray).fontSize(7).font('Helvetica')
          .text(`Signé le ${fmtDateShort(contract.guest_signed_at)} · IP: ${contract.guest_sign_ip || '—'}`, 50 + sigW + 20, y);
      }

      doc.rect(0, doc.page.height - 28, doc.page.width, 28).fill(lightBg);
      doc.fillColor(gray).fontSize(7).font('Helvetica')
        .text('Contrat généré via Boostinghost — www.boostinghost.fr', 0, doc.page.height - 18, { align: 'center', width: doc.page.width });

      doc.end();
      stream.on('finish', resolve);
      stream.on('error', reject);
    });

    const pdfBuffer = fs.readFileSync(pdfPath);
    try { fs.unlinkSync(pdfPath); } catch(e) {}

    const filename = `contrat_${isSigned ? 'signe_' : ''}${d.guestLastName?.toLowerCase() || 'location'}_${d.checkin || 'date'}.pdf`;
    res.set('Content-Type', 'application/pdf');
    res.set('Content-Disposition', `attachment; filename="${filename}"`);
    res.send(pdfBuffer);

  } catch (err) {
    console.error('❌ GET /api/contrats/:id/pdf:', err);
    res.status(500).json({ error: err.message });
  }
});

