// ============================================
// 🤖 HELPER POUR TRAITER LES MESSAGES ENTRANTS
// ============================================

/**
 * À appeler après chaque insertion de message guest dans la DB
 * Cette fonction gère automatiquement:
 * - L'onboarding (prénom, nom, téléphone, langue)
 * - Les réponses automatiques (mots-clés + Groq AI)
 */
async function processIncomingGuestMessage(savedMessage, conversationId) {
  try {
    // Ne traiter que les messages des clients
    if (savedMessage.sender_type !== 'guest') {
      return;
    }

    // Récupérer la conversation complète avec toutes les infos
    const convResult = await pool.query(
      'SELECT * FROM conversations WHERE id = $1',
      [conversationId]
    );

    if (convResult.rows.length === 0) {
      console.log('⚠️ Conversation introuvable:', conversationId);
      return;
    }

    const conversation = convResult.rows[0];

    // Traiter le message (onboarding + réponses auto)
    await handleIncomingMessage(savedMessage, conversation, pool, io);

  } catch (error) {
    console.error('❌ Erreur processIncomingGuestMessage:', error);
  }
}

// Exporter pour utilisation depuis d'autres fichiers
global.processIncomingGuestMessage = processIncomingGuestMessage;

// ============================================================
// 🔗 ROUTES CHANNEX
// ============================================================

// ── Connecter un logement à Channex ──────────────────────────
// ── Lister les propriétés Channex existantes ─────────────────
// ── Lister les channels connectés d'une property Channex ─────
app.get('/api/channex/connected-channels/:property_id', authenticateToken, async (req, res) => {
  const { property_id } = req.params;
  const user_id = req.user.id;
  try {
    const propResult = await pool.query(
      'SELECT channex_property_id, channex_enabled FROM properties WHERE id = $1 AND user_id = $2',
      [property_id, user_id]
    );
    const prop = propResult.rows[0];
    if (!prop || !prop.channex_enabled || !prop.channex_property_id) {
      return res.json({ channels: [] });
    }

    const { channexAPI } = require('./channex');

    // ✅ Récupère tous les channels sans filtre (Channex ignore filter[property_id])
    const response = await channexAPI.get('/channels', {
      params: { 'pagination[page_size]': 100, 'pagination[page]': 1 }
    });

    const raw = response.data?.data || [];

    // 🔍 Log complet pour debug
    console.log(`🔍 [CHANNEX channels] Total reçus: ${raw.length} | property_id cible: ${prop.channex_property_id}`);
    if (raw.length > 0) {
      console.log('🔍 [CHANNEX channels] Exemple item[0]:', JSON.stringify(raw[0], null, 2));
    } else {
      console.log('⚠️ [CHANNEX channels] Aucun channel retourné — vérifier la clé API / env');
    }

    // Filtrage robuste : property_id dans attributes OU relationships.properties.data[] (tableau)
    const filtered = raw.filter(c => {
      const fromAttr  = c.attributes?.property_id;
      const fromRel   = c.relationships?.property?.data?.id;  // singulier (ancien format)
      const fromRelArr = (c.relationships?.properties?.data || [])
                          .map(p => p.id);                     // ✅ tableau (format actuel Channex)
      const match = fromAttr === prop.channex_property_id
                 || fromRel  === prop.channex_property_id
                 || fromRelArr.includes(prop.channex_property_id);
      if (!match) console.log(`  ↳ skip channel ${c.id} (properties: ${fromRelArr.join(',') || fromAttr || fromRel || 'undefined'})`);
      return match;
    });

    console.log(`🔍 [CHANNEX channels] Après filtre property: ${filtered.length} channels`);
    // Récupérer le channex_rate_plan_id du logement pour filtrer le mapping
    const propRatePlan = await pool.query(
      'SELECT channex_rate_plan_id FROM properties WHERE id = $1',
      [property_id]
    );
    const ratePlanId = propRatePlan.rows[0]?.channex_rate_plan_id;

    const channels = filtered
      .map(c => ({
        id: c.id,
        title: c.attributes?.title || c.attributes?.name || '',
        status: c.attributes?.status || '',
        channel: (c.attributes?.channel || c.attributes?.channel_id || '').toLowerCase(),
        _rate_plan_ids: (c.attributes?.rate_plans || []).map(rp => rp.rate_plan_id)
      }))
      // Exclure les statuts explicitement inactifs
      .filter(c => !['disabled', 'deleted', 'inactive', 'paused'].includes(c.status))
      // ✅ Garder seulement les channels qui ont le rate_plan_id de CE logement
      .filter(c => {
        if (!ratePlanId || c._rate_plan_ids.length === 0) return true;
        const mapped = c._rate_plan_ids.includes(ratePlanId);
        if (!mapped) console.log(`  ↳ skip ${c.channel} — rate_plan ${ratePlanId} absent (a: ${c._rate_plan_ids.join(',')})`);
        return mapped;
      })
      .map(({ _rate_plan_ids, ...c }) => c);

    console.log(`✅ [CHANNEX channels] Résultat final pour ${prop.channex_property_id}:`, channels);

    res.json({ channels });
  } catch (e) {
    console.error('❌ [CHANNEX connected-channels]', e.message);
    res.json({ channels: [] });
  }
});

